namespace gea.interfaces.base {
    export interface IInterfaceDiscriminator {
        /**
         * 接口的辨别器
         * + 实现一个接口时，直接返回对应接口的字符串定义就可以
         * + 实现多个接口时，返回一个数组，包含多个接口的字符串定义
         * @see gea.discriminator.interfaces
         */
        readonly discriminator: string[] | string
    }
}
