namespace gea.decorators.base {
    export function finallyInvoke(callback: Function, scope?: any): Function {
        return function (target: any, methodName: any, desc: any) {
            let oMethod: Function = desc.value
            desc.value = function (...args: any[]) {
                oMethod.apply(this, args)
                callback.call(scope || this)
            }
        }
    }
}
