declare namespace hg {
    /**
     * 获取订阅状态,1000 的情况下才可订阅
     * code = 0 成功
     * code = -1 未知错误
     * code = 1000 未订阅
     * code = 1001 被封禁
     * code = 1002 不存在
     * code = 1003 已经订阅
     * @example
     * hg.subscribeGame({
     *  triggerType:1 //1:用户主动订阅；2:游戏引导；3:被动触发
     *  fail:function(code, msg) {
     *      console.log("subscribeGame fail " + code + " " + msg)
     *  },
     *  success:function(code, msg) {
     *      console.log("subscribeGame success " + code + " " + msg)
     *  }
     * })
     * @see https://open.ihago.net/resourceCenter?path=zh%2FgamePublic%2FsubscribeGame.html
     */
    function subscribeGame(opt: { triggerType: number, fail?: (code: number, msg: string) => void, success?: (code: number, msg: string) => void }): void
    /**
     * 取消订阅游戏
     * code = 0 成功
     * code = -1 未知错误
     * code = 1000 未订阅
     * code = 1001 被封禁
     * code = 1002 不存在
     * code = 1003 已经订阅
     * @example
     * hg.unsubscribeGame({
     *  fail:function(code, msg) {
     *      console.log("subscribeGame fail " + code + " " + msg)
     *  },
     *  success:function(code, msg) {
     *      console.log("subscribeGame success" + code + " " + msg)
     *  }
     * })
     */
    function unsubscribeGame(opt: { fail: (code: number, msg: string) => void, success: (code: number, msg: string) => void }): void
    /**
     * 获取订阅状态,1000 的情况下才可订阅
     * code = -1 未知错误
     * code = 1000 未订阅
     * code = 1001 被封禁
     * code = 1002 不存在
     * code = 1003 已经订阅
     * @example
     * hg.getGameSubscribeStatus({
     *  success:function(code) {
     *      console.log("getGameSubscribeStatus code " + code)
     *  }
     * })
     * @see https://open.ihago.net/resourceCenter?path=zh%2FgamePublic%2FsubscribeGame.html
     */
    function getGameSubscribeStatus(opt: { success: (code: number) => void }): void

    /**
     * 获取游戏打开场景回调
     * @param opt
     */
    function getOpenScene(opt: {
        callback?: (data: {
            openScene: number;
            from: string;
        }) => void;
    }): void;
}
