/// <reference path="../../../../gea-base/src/base/Gea.ts" />
/// <reference path="../interfaces/INet.ts" />
/// <reference path="../interfaces/INetParser.ts" />

namespace gea.abstracts.net {
    export abstract class NetParserBase implements interfaces.net.INetParser {
        protected _entity: gea.interfaces.net.INet | undefined
        protected _mapping: { [msgName: string]: { parser: any, [key: string]: any } } | undefined
        protected _encodeLogGenerator: ((opt: any) => any) | undefined
        protected _decodeLogGenerator: ((opt: any) => any) | undefined

        encode(netTag: string | number, sendData: any, ...args: any[]): interfaces.net.INetParserEncodeResult {
            throw new Error('please override in subClass!')
        }
        decode(recieveData: ArrayBuffer | Array<string | ArrayBuffer>): interfaces.net.INetParserDecodeResult {
            throw new Error('please override in subClass!')
        }
        setMapping(mapping: any): NetParserBase {
            this._mapping = mapping
            return this
        }
        setEncodeLogGenerator(callback: (opt: any) => any): NetParserBase {
            this._encodeLogGenerator = callback
            return this
        }
        setDecodeLogGenerator(callback: (opt: any) => any): NetParserBase {
            this._decodeLogGenerator = callback
            return this
        }

        destroy(): void {
            this._entity = undefined
            this._mapping = undefined
            this._encodeLogGenerator = undefined
            this._decodeLogGenerator = undefined
        }
    }
}
