/// <reference path="./interfaces/IUserInfoManager.ts" />

namespace hogame.utils {
    const DIC_USER_MORE_INFO: { [uid: string]: hg.IUserMoreInfo } = {}
    const DIC_FAILED_USER_MORE_INFO: { [uid: string]: hg.IUserMoreInfo } = {}
    const DIC_LOADING_RECORD: { [uid: string]: boolean } = {}
    const DIC_CALLBACK_INFO: { [uuid: string]: UserDataCallbackInfo } = {}
    const LIST_REQ: number[] = []
    let DEFAULT_USER_MORE_INFO: hg.IUserMoreInfo = { 'avatar': 'https://o-hk.ihago.net/ikxd/6727a572442261d5daa8ca3e012b441f/guest_1.png', 'birthday': '2000-01-01', 'nick': '\\br>😂😂😂😂test', 'sex': 1, 'uid': 101436495, 'zodiac': 0, city: 'Guangzhou', locationTude: '', personalType: hago.enums.userInfoType.debug }
    let defaultCount: number = 0
    let delayReqTime: number = 0
    let delayForEver: boolean = false
    let asyncTime: number = 1000
    class UserDataCallbackInfo {
        private _callback: (...infos: hg.IUserMoreInfo[]) => void
        private _callbackScope: any
        private _callbackArgs: any[]
        private _total: number
        private _progress: number
        private _listCallbackInfo: hg.IUserMoreInfo[] = []
        private _dicIndexRecord: { [uid: string]: number } = {}

        callbackBeforeRestore(): boolean {
            this._callback = null
            this._callbackScope = null
            if (this._callbackArgs != null) {
                this._callbackArgs.length = 0
                this._callbackArgs = null
            }
            this._listCallbackInfo.length = 0
            return true
        }

        checkProgress(info: hg.IUserMoreInfo): void {
            const index: number = this._dicIndexRecord[info.uid]
            if (index != null) {
                delete this._dicIndexRecord[info.uid]
                this._listCallbackInfo[index] = info
                if (++this._progress === this._total) {
                    delete DIC_CALLBACK_INFO[gea.uuid(this)]
                    this._callback.apply(this._callbackScope, this._callbackArgs.concat(this._listCallbackInfo))
                    gea.pool.restore(this)
                }
            }
        }

        callbackAfterBorrow(listUid: (string | number)[], callback: (...infos: hg.IUserMoreInfo[]) => void, callbackScope: any, callbackArgs: any[]): void {
            const listReq: number[] = []
            this._progress = 0
            let oldInfo: hg.IUserMoreInfo
            listUid.forEach((value: string | number, index: number): void => {
                oldInfo = DIC_USER_MORE_INFO[value]
                if (oldInfo != null) {
                    this._listCallbackInfo[index] = oldInfo
                    this._progress++
                } else {
                    if (window['hg']) {
                        // @ts-ignore
                        value = Number(value) || 0
                    } else {
                        // @ts-ignore
                        value = Number(value) || value
                    }
                    this._dicIndexRecord[value] = index
                    if (!DIC_LOADING_RECORD[value]) {
                        // @ts-ignore
                        listReq.push(value)
                        DIC_LOADING_RECORD[value] = true
                    }
                }
            })
            this._total = listUid.length
            if (this._progress === this._total) {
                callback.apply(callbackScope, callbackArgs.concat(this._listCallbackInfo))
                gea.pool.restore(this)
            } else {
                DIC_CALLBACK_INFO[gea.uuid(this)] = this
                this._callback = callback
                this._callbackScope = callbackScope
                this._callbackArgs = callbackArgs
                if (listReq.length > 0) {
                    if (window['hg']) {
                        if (LIST_REQ.length === 0) {
                            if (delayReqTime > 0) {
                                gea.timer.once(delayReqTime, getUserInfoFromApp, this)
                            } else {
                                gea.polling.once(getUserInfoFromApp, this)
                            }
                        }
                        LIST_REQ.push.apply(LIST_REQ, listReq)
                    } else {
                        getUserInfoFromLocal(listReq)
                    }
                }
            }
        }
    }
    class UserInfoManager implements hogame.interfaces.utils.IUserInfoManager {
        default(info?: hg.IUserMoreInfo): UserInfoManager | hg.IUserMoreInfo {
            if (info != null) {
                DEFAULT_USER_MORE_INFO = info
            } else {
                return DEFAULT_USER_MORE_INFO
            }
            return this
        }

        delayTime(time: number = 200, forever: boolean = false): UserInfoManager {
            delayReqTime = time
            delayForEver = forever
            return this
        }

        get(uid: (string | number) | (string | number)[], callback: (...infos: hg.IUserMoreInfo[]) => void, callbackScope?: any, ...callbackArgs: any[]): UserInfoManager {
            if (uid instanceof Array) {
                if (uid.length > 0) {
                    gea.pool.borrow(UserDataCallbackInfo, Array.from(new Set(uid)), callback, callbackScope, callbackArgs)
                }
            } else if (uid) {
                gea.pool.borrow(UserDataCallbackInfo, [uid], callback, callbackScope, callbackArgs)
            }
            return this
        }

        asyncTime(value: number): UserInfoManager {
            asyncTime = Math.max(value, 500)
            return this
        }
    }

    function userInfoGeted(info: hg.IUserMoreInfo): void {
        delete DIC_LOADING_RECORD[info.uid]
        DIC_USER_MORE_INFO[info.uid] = info
        for (let uuid in DIC_CALLBACK_INFO) {
            DIC_CALLBACK_INFO[uuid].checkProgress(info)
        }
    }

    function userInfoFailed(uid: number): void {
        delete DIC_LOADING_RECORD[uid]
        let failedInfo: hg.IUserMoreInfo = DIC_FAILED_USER_MORE_INFO[uid]
        if (failedInfo == null) {
            failedInfo = {
                uid: uid,
                avatar: DEFAULT_USER_MORE_INFO.avatar,
                birthday: DEFAULT_USER_MORE_INFO.birthday,
                nick: 'unknown',
                sex: hago.enums.sex.female,
                zodiac: hago.enums.constellation.aquarius,
                locationTude: DEFAULT_USER_MORE_INFO.locationTude,
                city: DEFAULT_USER_MORE_INFO.city,
                personalType: hago.enums.userInfoType.unknow,
            }
            DIC_FAILED_USER_MORE_INFO[uid] = failedInfo
        }
        for (let uuid in DIC_CALLBACK_INFO) {
            DIC_CALLBACK_INFO[uuid].checkProgress(failedInfo)
        }
    }

    function getUserInfoFromLocal(listReq: number[]): void {
        gea.timer.once(asyncTime, (): void => {
            let info: hg.IUserMoreInfo
            listReq.forEach((value: number): void => {
                info = {
                    avatar: DEFAULT_USER_MORE_INFO.avatar,
                    birthday: DEFAULT_USER_MORE_INFO.birthday,
                    nick: (defaultCount++) + DEFAULT_USER_MORE_INFO.nick,
                    sex: Math.random() > 0.5 ? 0 : 1,
                    uid: value,
                    zodiac: 0,
                    city: 'Guangzhou',
                    locationTude: '',
                    personalType: hago.enums.userInfoType.debug,
                }
                userInfoGeted(info)
            })
        }, this)
    }


    function getUserInfoFromApp(): void {
        if (!delayForEver) {
            delayReqTime = 0
        }
        const listReq: number[] = LIST_REQ.concat()
        LIST_REQ.length = 0
        hg.getUserInfoByUids({
            uids: listReq,
            success: (res: hg.IUserMoreInfo[]): void => {
                res.forEach((value: hg.IUserMoreInfo): void => {
                    // @ts-ignore
                    value.personalType = hago.enums.userInfoType.valid
                    userInfoGeted(value)
                    listReq.splice(listReq.indexOf(value.uid), 1)
                })
                if (listReq.length > 0) {
                    gea.error(`hg.getUserInfoByUids failed uids: [${listReq.join(', ')}], will use unknown info to callback`)
                    listReq.forEach((uid: number): void => {
                        userInfoFailed(uid)
                    })
                }
            },
            fail: (res: { errCode: number }): void => {
                gea.error('hg.getUserInfoByUids failed! errMsg:', JSON.stringify(res || {}), `listReq: [${listReq.join(',')}], will use unknown infos to callback`)
                listReq.forEach((value: number): void => {
                    userInfoFailed(value)
                })
            },
        })
    }

    export const userInfo: hogame.interfaces.utils.IUserInfoManager = new UserInfoManager()
}
