/// <reference path="../interfaces/IPoolObject.ts" />
/// <reference path="../interfaces/ICallback.ts" />
/// <reference path="../Callback.ts" />
/// <reference path="../UUID.ts" />

namespace gea.utility.dispatcher {
    class Dispatcher implements gea.interfaces.base.IPoolObject {
        private _mapCallbacksByTag: Map<string, Map<string, gea.interfaces.base.ICallback>> = new Map()
        private _mapCallbacksByScope: Map<string, Map<string, Set<string>>> = new Map()
        callbackAfterBorrow(): Dispatcher {
            return this
        }

        callbackBeforeRestore(): boolean {
            // this._mapCallbacks.clear()
            return true
        }

        once(tag: any, callback: Function, scope: any, ...callbackArgs: any[]): Dispatcher {
            this.register(false, tag, 1, callback, scope, ...callbackArgs)
            return this
        }

        oncePrior(tag: any, callback: Function, scope: any, ...callbackArgs: any[]): Dispatcher {
            this.register(true, tag, 1, callback, scope, ...callbackArgs)
            return this
        }

        on(tag: any, callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Dispatcher {
            this.register(false, tag, callbackLimite, callback, scope, ...callbackArgs)
            return this
        }

        onPrior(tag: any, callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Dispatcher {
            this.register(true, tag, callbackLimite, callback, scope, ...callbackArgs)
            return this
        }

        off(tag: any, callback: Function, scope: any): Dispatcher {
            this.deRegister(false, tag, callback, scope).deRegister(true, tag, callback, scope)
            return this
        }

        offByScope(scope: any): Dispatcher {
            const uuidScope: string = gea.uuid(scope)
            const mapScope: Map<string, Set<string>> = this._mapCallbacksByScope.get(uuidScope)
            if (mapScope) {
                mapScope.forEach((setCallback: Set<string>, uuidTag: string): void => {
                    setCallback.forEach(uuidCallback => {
                        this.deRegisterByUuid(uuidTag, uuidCallback, uuidScope)
                    })
                })
            }
            return this
        }

        dispatch(tag: any, ...args: any[]): Dispatcher {
            const uuidTag: string = gea.uuid(tag)
            this.dispatchDetail(`prior_${uuidTag}`, ...args).dispatchDetail(uuidTag, ...args)
            return this
        }

        private dispatchDetail(uuidTag: string, ...args: any[]): Dispatcher {
            const mapTag: Map<string, gea.interfaces.base.ICallback> = this._mapCallbacksByTag.get(uuidTag)
            if (mapTag !== undefined) {
                mapTag.forEach((callback: gea.interfaces.base.ICallback, uuidCallback: string): void => {
                    callback.excute(...args)
                    if (callback.callbackLimite() === 0) {
                        this.deRegisterByUuid(uuidTag, uuidCallback, uuidCallback.split('_')[0])
                    }
                })
            }
            return this
        }

        private register(prior: boolean, tag: any, callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Dispatcher {
            if (callbackLimite.constructor !== Number) {
                if (scope != null || callbackArgs.length > 0) {
                    callbackArgs.unshift(scope)
                }
                scope = callback
                callback = <Function>callbackLimite
                callbackLimite = 0
            }
            const uuidTag: string = prior ? `prior_${gea.uuid(tag)}` : gea.uuid(tag)
            let mapTag: Map<string, gea.interfaces.base.ICallback> = this._mapCallbacksByTag.get(uuidTag)
            if (mapTag === undefined) {
                mapTag = new Map()
                this._mapCallbacksByTag.set(uuidTag, mapTag)
            }
            const uuidCallback = gea.uuid(callback, scope)
            if (scope != null) {
                const uuidScope = gea.uuid(scope)
                let mapScope: Map<string, Set<string>> = this._mapCallbacksByScope.get(uuidScope)
                if (mapScope === undefined) {
                    mapScope = new Map()
                    this._mapCallbacksByScope.set(uuidScope, mapScope)
                }
                let setCallback: Set<string> = mapScope.get(uuidTag)
                if (setCallback === undefined) {
                    setCallback = new Set()
                    mapScope.set(uuidTag, setCallback)
                }
                setCallback.add(uuidCallback)
            }
            let callbackTmp: gea.interfaces.base.ICallback = mapTag.get(uuidCallback)
            if (callbackTmp === undefined) {
                callbackTmp = gea.callback(callback, scope, ...callbackArgs).callbackLimite(<number>callbackLimite)
                mapTag.set(uuidCallback, callbackTmp)
            } else {
                callbackTmp.args(...callbackArgs).callbackLimite(<number>callbackLimite)
            }
            return this
        }

        private deRegister(prior: boolean, tag: any, callback: Function, scope: any): Dispatcher {
            this.deRegisterByUuid(prior ? `prior_${gea.uuid(tag)}` : gea.uuid(tag), gea.uuid(callback, scope), gea.uuid(scope))
            return this
        }

        private deRegisterByUuid(uuidTag: string, uuidCallback: string, uuidScope: string): void {
            const mapTag: Map<string, gea.interfaces.base.ICallback> = this._mapCallbacksByTag.get(uuidTag)
            if (mapTag !== undefined) {
                const callbackTmp: gea.interfaces.base.ICallback = mapTag.get(uuidCallback)
                if (callbackTmp !== undefined) {
                    mapTag.delete(uuidCallback)
                    callbackTmp.destroy()
                    if (mapTag.size === 0) {
                        this._mapCallbacksByTag.delete(uuidTag)
                    }
                }
            }

            const mapScope: Map<string, Set<string>> = this._mapCallbacksByScope.get(uuidScope)
            if (mapScope !== undefined) {
                const setCallback: Set<string> = mapScope.get(uuidTag)
                if (setCallback && setCallback.delete(uuidCallback)) {
                    if (setCallback.size === 0) {
                        mapScope.delete(uuidTag)
                        if (mapScope.size === 0) {
                            this._mapCallbacksByScope.delete(uuidScope)
                        }
                    }
                }
            }
        }
    }
    /**
     * 存储已装载的Dispatcher对象
     */
    const mapDispatcher: Map<string, Dispatcher> = new Map()

    function callDispatcher(instance: any, method: 'once' | 'oncePrior' | 'on' | 'onPrior' | 'off' | 'offByScope' | 'dispatch', ...args: any[]): void {
        let disPatcher: Dispatcher = mapDispatcher.get(gea.uuid(instance))
        if (disPatcher !== undefined) {
            disPatcher[method].call(disPatcher, ...args)
        } else {
            disPatcher = gea.pool.borrow(Dispatcher)
            mapDispatcher.set(gea.uuid(instance), disPatcher)
            disPatcher[method].call(disPatcher, ...args)
        }
    }

    export function once(dispatcher: any, tag: any, callback: Function, scope: any, ...callbackArgs: any[]): void {
        callDispatcher(dispatcher, 'once', tag, callback, scope, ...callbackArgs)
    }

    export function oncePrior(dispatcher: any, tag: any, callback: Function, scope: any, ...callbackArgs: any[]): void {
        callDispatcher(dispatcher, 'oncePrior', tag, callback, scope, ...callbackArgs)
    }

    export function on(dispatcher: any, tag: any, callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): void {
        callDispatcher(dispatcher, 'on', tag, callbackLimite, callback, scope, ...callbackArgs)
    }

    export function onPrior(dispatcher: any, tag: any, callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): void {
        callDispatcher(dispatcher, 'onPrior', tag, callbackLimite, callback, scope, ...callbackArgs)
    }

    export function off(dispatcher: any, tag: any, callback: Function, scope: any): void {
        callDispatcher(dispatcher, 'off', tag, callback, scope)
    }

    /**
     * 移除`scope`下的所有订阅者
     * @param scope 指定作用域
     * @param dispatcher 指定的dispatcher实例，如果这个值为空，则表示移除调所有dispather下的订阅者
     */
    export function offByScope(scope: any, dispatcher?: any): void {
        if (dispatcher != null) {
            callDispatcher(dispatcher, 'offByScope', scope)
        } else {
            mapDispatcher.forEach(dispatcher => {
                callDispatcher(dispatcher, 'offByScope', scope)
            })
        }
    }

    export function dispatch(dispatcher: any, tag: any, ...args: any[]): void {
        callDispatcher(dispatcher, 'dispatch', tag, ...args)
    }
}
