/// <reference path="./UUID.ts" />
/// <reference path="./interfaces/IPolling.ts" />
/// <reference path="./Gea.ts" />

namespace gea {
    class Polling implements interfaces.base.IPolling {
        get frameRate(): number {
            return this._framRate
        }
        set frameRate(value: number) {
            if (value !== this._framRate) {
                this._framRate = value
                this._timerCostPerFrame = Math.floor(1000 / this._framRate)
                this.frameRateChanged()
            }
        }
        private _framRate: number = NaN
        private _timerCostPerFrame = 1000 / this._framRate
        private _prevAnimationTime: number = 0
        private _requestAniFrame: Function = null
        private _animationCallback: Function = null

        constructor() {
            this._animationCallback = this.animationFrameCallback.bind(this)
            this.frameRate = 60
        }

        once(callback: Function, scope: any, ...callbackArgs: any[]): Polling {
            gea.utility.dispatcher.once(this, 'gea.adapter.polling', callback, scope, ...callbackArgs)
            return this
        }

        // on(callback: Function, scope: any, ...callbackArgs: any[]): Polling
        on(callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Polling {
            gea.utility.dispatcher.on(this, 'gea.adapter.polling', callbackLimite, callback, scope, ...callbackArgs)
            return this
        }

        off(callback: Function, scope: any): Polling {
            gea.utility.dispatcher.off(this, 'gea.adapter.polling', callback, scope)
            return this
        }

        oncePrior(callback: Function, scope: any, ...callbackArgs: any[]): Polling {
            gea.utility.dispatcher.oncePrior(this, 'gea.adapter.polling', callback, scope, ...callbackArgs)
            return this
        }

        onPrior(callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Polling {
            gea.utility.dispatcher.onPrior(this, 'gea.adapter.polling', callbackLimite, callback, scope, ...callbackArgs)
            return this
        }

        offByScope(scope: any): Polling {
            gea.utility.dispatcher.offByScope(scope, this)
            return this
        }

        private animationFrameCallback(): void {
            const curTime: number = gea.instance.pastTime
            const pastTime = curTime - this._prevAnimationTime
            this._prevAnimationTime = curTime
            if (!gea.instance.paused) {
                gea.utility.dispatcher.dispatch(this, 'gea.adapter.polling', pastTime)
            }
            this._requestAniFrame(this._animationCallback)
        }

        private requestAnimationFrame() {
            const curTime: number = gea.instance.pastTime
            const pastTime: number = curTime - this._prevAnimationTime
            const delayTime: number = Math.max(this._timerCostPerFrame - pastTime)
            window.setTimeout((): void => {
                this.animationFrameCallback()
            }, delayTime)
            this._prevAnimationTime = curTime + delayTime
        }

        private frameRateChanged() {
            if (60 % this._framRate !== 0) {
                this._requestAniFrame = this.requestAnimationFrame
            } else {
                this._requestAniFrame = window.requestAnimationFrame.bind(window) ||
                    window.webkitRequestAnimationFrame.bind(window) ||
                    window['mozRequestAnimationFrame'].bind(window) ||
                    window['oRequestAnimationFrame'].bind(window) ||
                    window['msRequestAnimationFrame'].bind(window) ||
                    this.requestAnimationFrame
            }
            this._prevAnimationTime = gea.instance.pastTime
            this.animationFrameCallback()
        }
    }
    export const polling: interfaces.base.IPolling = new Polling()
}
