namespace hago.friend {
    const DIC_ADDED: { [uid: string]: number } = {}
    /**
     * 添加好友
     * @param uid 要添加的玩家uid
     * @param callbackSuccess 成功回调 本地调试时有50%几率成功
     * @param callbackFailed 失败回调 本地调试时有50%几率失败
     */
    export function addFriend(uid: string | number, callback?: (uid: string | number, success: boolean, code: number) => void): void {
        if (window['hg']) {
            if (hg.addFriend) {
                const addedCode: number = DIC_ADDED[uid]
                if (!addedCode) {
                    hg.addFriend({
                        uid: Number(uid),
                        success: (res: { code: number }): void => {
                            DIC_ADDED[uid] = res.code
                            callback(uid, true, res.code)
                        },
                        fail: (res: { code: number }): void => {
                            callback(uid, false, res.code)
                        },
                    })
                } else {
                    callback(uid, true, addedCode)
                }
            }
        } else {
            gea.info(`hg.addFriend: ${uid}`)
            if (Math.random() > 0.5) {
                callback(uid, true, 1)
            } else {
                callback(uid, false, 321)
            }
        }
    }
}
