/// <reference path="./interfaces/IGea.ts" />
/// <reference path="./Event.ts" />
/// <reference path="./utility/Dispatcher.ts" />
/// <reference path="./decorators/Singleton.ts" />

namespace gea {
    let PAST_TIME: number = 0
    let PREV_TIME: number = Date.now()
    const PAST_TIME_OBJ: { now: () => number } = window.performance || {
        now: (): number => {
            const now: number = Date.now()
            if (now < PREV_TIME) {
                PAST_TIME += 16
            } else {
                PAST_TIME += now - PREV_TIME
            }
            PREV_TIME = now

            return PAST_TIME
        },
    }
    const START_TIME: number = Math.round(window.performance && window.performance.timing && window.performance.timing.navigationStart || (Date.now() - PAST_TIME_OBJ.now()))
    @decorators.base.singleton
    class Gea implements interfaces.base.IGea {
        private _paused: boolean = false
        constructor() {
            if (document != null) {
                document.addEventListener('visibilitychange', (event: Event): void => {
                    gea.info('visibilitychange', 'hidden = ' + (event['hidden'] || document.hidden))
                    if (document.hidden || event['hidden']) {
                        this.dispatch(gea.events.base.enter_background)
                    } else {
                        this.dispatch(gea.events.base.enter_foreground)
                    }
                })
            }
        }

        get paused(): boolean {
            return this._paused
        }

        get localTime(): number {
            return START_TIME + this.pastTime
        }

        get pastTime(): number {
            return Math.floor(PAST_TIME_OBJ.now())
        }

        pause(): void {
            if (this._paused === false) {
                this._paused = true
            }
        }

        resume(): void {
            if (this._paused === true) {
                this._paused = false
            }
        }

        once(tag: any, callback: Function, scope: any, ...callbackArgs: any[]): Gea {
            gea.utility.dispatcher.once(this, tag, callback, scope, ...callbackArgs)
            return this
        }

        oncePrior(tag: any, callback: Function, scope: any, ...callbackArgs: any[]): Gea {
            gea.utility.dispatcher.oncePrior(this, tag, callback, scope, ...callbackArgs)
            return this
        }

        on(tag: any, callbackLimit: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Gea {
            gea.utility.dispatcher.on(this, tag, callbackLimit, callback, scope, ...callbackArgs)
            return this
        }

        onPrior(tag: any, callbackLimit: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Gea {
            gea.utility.dispatcher.onPrior(this, tag, callbackLimit, callback, scope, ...callbackArgs)
            return this
        }

        off(tag: any, callback: Function, scope: any): Gea {
            gea.utility.dispatcher.off(this, tag, callback, scope)
            return this
        }

        offByScope(scope: any): Gea {
            gea.utility.dispatcher.offByScope(scope, this)
            return this
        }

        dispatch(tag: any, ...args: any[]): Gea {
            gea.utility.dispatcher.dispatch(this, tag, ...args)
            return this
        }
    }
    /**
     * @see gea.interfaces.base.IGea
     */
    export const instance: interfaces.base.IGea = new Gea()
}
