/// <reference path="./interfaces/IStringUtils.ts" />

namespace gea.utils {
    class StringUtils implements gea.interfaces.utils.IStringUtils {
        subUtf8(str: string, len: number, tailSymbol: string = '...'): string {
            const strArray: string[] = [...str]
            if (strArray.length > len) {
                return strArray.slice(0, len).join('') + tailSymbol
            }
            return str
        }

        utf8len(str: string): number {
            return [...str].length
        }
    }

    export const str: gea.interfaces.utils.IStringUtils = new StringUtils()
}
