/// <reference path="../UUID.ts" />
/// <reference path="../Log.ts" />

namespace gea.utility.entity {
    /**
     * 实体组件字典
     */
    const mapEntities: Map<string, Map<string, any>> = new Map()
    /**
     * 添加一个组件依附于当前实体
     * + 同一个类型的组件只能在同一个实体上添加一个
     * @param entity 实体
     * @param component 组件实例
     */
    export function addComponent<T>(entity: any, component: T): T {
        if (entity) {
            const uuidEntity: string = gea.uuid(entity)
            const uuidComponent: string = gea.uuid(component.constructor)
            let mapComponents: Map<string, T> = mapEntities.get(uuidEntity)
            if (mapComponents === undefined) {
                mapComponents = new Map()
                mapEntities.set(uuidEntity, mapComponents)
            }
            if (!mapComponents.has(uuidComponent)) {
                mapComponents.set(uuidComponent, component)
            } else {
                gea.warn(`a same component should only add once on the same entity`)
            }
        } else {
            // null, undefined, ''
            gea.warn(`entity is empty, addComponent failed!`)
        }
        return component
    }

    /**
     * 获取当前实体上的某个组件
     * @param compClass 组件class
     * @param matchPrototype 当通过`compClass`找不到组件时，是否按原型链匹配的方式查找
     * + 当实体上有多个组件的原型与传入的`compClass`相匹配时，始终返回第一个匹配到的值
     * @example
     * class BaseComponent {}
     * class SubComponent extends BaseComponent{}
     * const comp = new SubComponent()
     * gea.utility.base.entiry.addComponent('testEntity', comp)
     * gea.utility.base.entiry.getComponent('testEntity', SubComponent);       //通过子类型自身获取:comp
     * gea.utility.base.entiry.getComponent('testEntity', BaseComponent);      //通过父类型获取，不匹配原型链:undefined
     * gea.utility.base.entiry.getComponent('testEntity', BaseClass, true);    //通过父类型获取，匹配原型链:comp
     */
    export function getComponent<T>(entity: any, compClass: { prototype: T }, matchPrototype?: boolean): T {
        if (entity) {
            const uuidEntity: string = gea.uuid(entity)
            const mapComponents: Map<string, T> = mapEntities.get(uuidEntity)
            if (mapComponents !== undefined) {
                const uuidComponent: string = gea.uuid(compClass)
                let result = mapComponents.get(uuidComponent)
                if (result === undefined && matchPrototype) {
                    for (let comp of mapComponents.values()) {
                        // @ts-ignore
                        if (comp instanceof compClass) {
                            result = comp
                            break
                        }
                    }
                }
                return <T>result
            }
        } else {
            // null, undefined, ''
            gea.warn(`entity is empty, getComponent failed!`)
        }
        return undefined
    }

    /**
     * 移除当前实体上的某个组件
     * @param compClass 组件class
     * @param matchPrototype 当通过`compClass`找不到组件时，是否按原型链匹配的方式查找
     * + 当实体上有多个组件的原型与传入的`compClass`相匹配时，始终返回第一个匹配到的值
     * @example
     * class BaseComponent {}
     * class SubComponent extends BaseComponent{}
     * const comp = new SubComponent()
     * gea.utility.base.entiry.addComponent('testEntity', comp)
     * gea.utility.base.entiry.removeComponent('testEntity', SubComponent);       //通过子类型自身删除:comp
     * gea.utility.base.entiry.removeComponent('testEntity', BaseComponent);      //通过父类型删除，不匹配原型链:undefined
     * gea.utility.base.entiry.removeComponent('testEntity', BaseClass, true);    //通过父类型删除，匹配原型链:comp
     */
    export function removeComponent<T>(entity: any, compClass: { prototype: T, new(): T }, matchPrototype?: boolean): T {
        if (entity) {
            const uuidEntity: string = gea.uuid(entity)
            const mapComponents: Map<string, T> = mapEntities.get(uuidEntity)
            if (mapComponents !== undefined) {
                const uuidComponent: string = gea.uuid(compClass)
                let result = mapComponents.get(uuidComponent)
                if (result === undefined && matchPrototype) {
                    for (let comp of mapComponents.values()) {
                        if (comp instanceof compClass) {
                            result = comp
                            break
                        }
                    }
                }
                return result
            }
        } else {
            // null, undefined, ''
            gea.warn(`entity is empty, removeComponent failed`)
        }
        return undefined
    }
}
