/// <reference path="../../../gea/gea-net/src/net/abstracts/NetParserBase.ts" />
/// <reference path="../../../gea/gea-net/src/net/interfaces/INetParser.ts" />
/// <reference path="./interfaces/IGmeNet.ts" />
/// <reference path="../../../gea/gea-base/src/base/utility/Entity.ts" />

namespace gea {
    let CONN_ID = 0
    const MESSAGE_ENTER_ROOM: string = 'net.ihago.gme.srv.sidecar_gateway.GMEInternalEnterRoom'
    const MESSAGE_LEAVE_ROOM: string = 'net.ihago.gme.srv.sidecar_gateway.GMEInternalLeaveRoom'
    const MESSAGE_PING: string = 'reserved.gateway.ping'
    class NetParser extends gea.abstracts.net.NetParserBase {
        private _upStream: interfaces.net.UpStream
        private _downStream: interfaces.net.DownStream
        private _mapRoomId: Map<string, string> = new Map()
        private _commonRoomId: string
        encode(messageName: string, sendData: any, path: string, roomId: string): gea.interfaces.net.INetParserEncodeResult {
            const resultBody: Uint8Array = this._mapping[messageName].parser.encode(sendData).finish()
            const bufferBody: ArrayBuffer = resultBody.buffer.slice(resultBody.byteOffset, resultBody.byteOffset + resultBody.byteLength)

            path = path || this._mapping[messageName].path

            if (messageName !== MESSAGE_ENTER_ROOM) {
                roomId = roomId || this._mapRoomId.get(path) || (messageName === MESSAGE_PING && '')
            } else {
                roomId = roomId || this.commonRoomId
                this._mapRoomId.set(path, roomId)
            }

            this._upStream.path = path
            this._upStream.body_name = messageName
            this._upStream.body = new Uint8Array(bufferBody)
            this._upStream.seq++
            this._upStream.uid = <string>(<interfaces.net.IGmeNet>this._entity).uid
            this._upStream.room_id = roomId

            const resultUpStream: Uint8Array = this._mapping.Upstream.parser.encode(this._upStream).finish()
            const bufferUpStream: ArrayBuffer = resultUpStream.buffer.slice(resultUpStream.byteOffset, resultUpStream.byteOffset + resultUpStream.byteLength)

            const sendAble: boolean = roomId === '' || !!roomId

            const encodeResult: gea.interfaces.net.INetParserEncodeResult = {
                sendAble: sendAble,
                msg: messageName,
                data: bufferUpStream,
                log: `${messageName} ${sendData} ${JSON.stringify(this._upStream, (key, value): any => {
                    if (key === 'body') {
                        return null
                    }
                    return value
                })}`,
            }

            if (!sendAble) {
                gea.error(`消息${messageName}属于'${path}'模块,当前未加入该模块,请调用网络实例的'enterRoom方法'加入该模块后才能成功发送该消息到服务器`)
                encodeResult.log = null
            } else {
                if (this._encodeLogGenerator) {
                    encodeResult.log = this._encodeLogGenerator({
                        msg: messageName,
                        body: sendData,
                        upStream: JSON.parse(JSON.stringify(this._upStream, (key, value): any => {
                            if (key !== 'body') {
                                return value
                            }
                        })),
                    })
                }
                // 本地调试的时候打印对象，方便查看
                else if (!window['hg']) {
                    encodeResult.log = {
                        msg: messageName,
                        body: sendData,
                        upStream: JSON.parse(JSON.stringify(this._upStream, (key, value): any => {
                            if (key !== 'body') {
                                return value
                            }
                        })),
                    }
                }
            }

            return encodeResult
        }

        decode(recieveData: ArrayBuffer): gea.interfaces.net.INetParserDecodeResult {
            const startTime: number = gea.instance.pastTime
            this._downStream = this._mapping.Downstream.parser.decode(new Uint8Array(recieveData))
            const msgKey: string = this._downStream.body_name || this._downStream.path
            if (this._mapping[msgKey]) {
                const decodeedData: any = this._mapping[msgKey].parser.decode(this._downStream.body)
                const costTime: number = gea.instance.pastTime - startTime

                const decodeResult: gea.interfaces.net.INetParserDecodeResult = {
                    decodeTime: costTime,
                    msg: msgKey,
                    data: decodeedData,
                    log: `${msgKey} decodeTime: ${costTime}, ${JSON.stringify(decodeedData)} ${JSON.stringify(this._downStream, (key, value): any => {
                        if (key === 'body') {
                            return null
                        }
                        return value
                    })}`,
                    args: [this._downStream],
                }

                if (msgKey === MESSAGE_LEAVE_ROOM) {
                    if (decodeedData.uid) {
                        if (decodeedData.uid === hogame.config.uid) {
                            this._mapRoomId.delete(this._downStream.path);
                        }
                    }
                } else if (msgKey === MESSAGE_ENTER_ROOM) {
                    this._mapRoomId.set(this._downStream.path, this._downStream.room_id)
                }


                if (this._decodeLogGenerator) {
                    decodeResult.log = this._decodeLogGenerator({
                        msg: msgKey,
                        decodeTime: costTime,
                        body: decodeedData,
                        downStream: this._downStream,
                    })
                }
                // 本地调试的时候打印对象，方便查看
                else if (!window['hg']) {
                    decodeResult.log = {
                        msg: msgKey,
                        decodeTime: costTime,
                        body: decodeedData,
                        downStream: JSON.parse(JSON.stringify(this._downStream, (key, value): any => {
                            if (key !== 'body') {
                                return value
                            }
                        })),
                    }
                }
                return decodeResult
            }
            gea.warn(`${msgKey}找不到对应的解析函数,请确认前后端proto文件是否一致`, JSON.stringify(this._downStream))
            return null
        }

        callbackAfterBorrow(net: interfaces.net.INet): void {
            this._entity = net
            this._upStream = { content_type: 'application/protobuf', seq: 0, conn_id: (++CONN_ID).toString() }
            this._downStream = {}
        }

        callbackBeforeRestore(): boolean {
            this._commonRoomId = undefined
            this._upStream = undefined
            this._downStream = undefined
            this._mapRoomId.clear()
            return true
        }

        destroy(): void {
            super.destroy()
            gea.pool.restore(this)
        }

        private get commonRoomId(): string {
            if (this._commonRoomId === undefined) {
                this._commonRoomId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
                    const r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8)
                    return v.toString(16)
                }) + <string>(<interfaces.net.IGmeNet>this._entity).uid
            }
            return this._commonRoomId
        }
    }

    gea.instance
        .on('gea.events.net.callbackAfterBorrow', (net: gea.interfaces.net.IGmeNet): void => {
            gea.utility.entity.addComponent(net, gea.pool.borrow(NetParser, net))
        }, window)
        .on('gea.events.net.callbackBeforeRestore', (net: gea.interfaces.net.IGmeNet): void => {
            gea.utility.entity.removeComponent(net, NetParser).destroy()
        }, window)

    if (gea.net) {
        gea.utility.entity.addComponent(gea.net, gea.pool.borrow(NetParser, gea.net))
    }
}
