/// <reference path="./interfaces/IFriendInfoManager.ts" />
/// <reference path="../Config.ts" />
/// <reference path="../../../../gea/gea-base/src/base/Callback.ts" />
/// <reference path="../../../../gea/gea-base/src/base/Timer.ts" />

namespace hogame.utils {
    class FriendInfoManager implements hogame.utils.IFriendInfoManager {
        private _dicFriendInfo: { [uid: string]: hg.IFriendInfo } = {}
        private _listFriendInfo: hg.IFriendInfo[]

        private _listAllCallbackSuccess: gea.interfaces.base.ICallback[] = []
        private _dicAllCallbackSuccessRecord: { [uuid: string]: true } = {}
        private _listAllCallbackFailed: gea.interfaces.base.ICallback[] = []
        private _dicAllCallbackFailedRecord: { [uuid: string]: true } = {}

        private _asyncTime: number = 1000
        private _retryCount: number = 3
        private _retryDelay: number = 1000
        private _gettingCount: number = 0
        default(...friendInfos: hg.IFriendInfo[]): FriendInfoManager {
            if (!window['hg']) {
                this._listFriendInfo = []
                friendInfos.forEach((info: hg.IFriendInfo, index: number): void => {
                    this._listFriendInfo[index] = this.defaultInfo(info)
                    this._dicFriendInfo[info.uid] = info
                })
            }
            return this
        }

        retryCount(value: number): FriendInfoManager {
            this._retryCount = Math.max(0, value)
            return this
        }

        retryDelay(value: number): FriendInfoManager {
            this._retryDelay = Math.max(0, value)
            return this
        }

        asyncTime(value: number): FriendInfoManager {
            this._asyncTime = Math.max(500, value)
            return this
        }

        get(
            callbackSuccess: (...friendInfos: hg.IFriendInfo[]) => void,
            callbackScopeWhileSuccess?: any,
            callbackFailed?: () => void,
            callbackScopeWhileFailed?: any,
        ): void {
            if (window['hg']) {
                if (this._listFriendInfo != null) {
                    if (callbackSuccess) {
                        callbackSuccess.call(callbackScopeWhileSuccess, ...this._listFriendInfo)
                    }
                } else {
                    let uuid: string
                    if (callbackSuccess) {
                        uuid = gea.uuid(callbackSuccess, callbackScopeWhileSuccess)
                        if (!this._dicAllCallbackSuccessRecord[uuid]) {
                            this._dicAllCallbackSuccessRecord[uuid] = true
                            this._listAllCallbackSuccess.push(gea.callback(callbackSuccess, callbackScopeWhileSuccess).callbackLimite(1))
                        }
                    }
                    if (callbackFailed) {
                        uuid = gea.uuid(callbackFailed, callbackScopeWhileFailed)
                        if (!this._dicAllCallbackFailedRecord[uuid]) {
                            this._dicAllCallbackFailedRecord[uuid] = true
                            this._listAllCallbackFailed.push(gea.callback(callbackFailed, callbackScopeWhileFailed).callbackLimite(1))
                        }
                    }
                    this.getFromApp()
                }
            } else {
                if (this._asyncTime > 0) {
                    gea.timer.once(this._asyncTime, (): void => {
                        this._asyncTime = 0
                        callbackSuccess.call(callbackScopeWhileSuccess, ...this._listFriendInfo)
                    }, this)
                } else {
                    callbackSuccess.call(callbackScopeWhileSuccess, ...this._listFriendInfo)
                }
            }
        }

        getByUid(
            uid: string | number,
            callbackScuccess: (friendInfo: hg.IFriendInfo) => void,
            callbackScopeWhileSuccess?: any,
            callbackFailed?: () => void,
            callbackScopeWhileFailed?: any,
        ): void {
            this.get((): void => {
                callbackScuccess.call(callbackScopeWhileSuccess, this._dicFriendInfo[uid])
            }, this, callbackFailed, callbackScopeWhileFailed)
        }

        private getFromApp(): void {
            if (this._gettingCount === 0) {
                this.retryGetFromApp()
            }
        }

        private retryGetFromApp(friendError?: hg.IFriendError): void {
            if (this._gettingCount <= this._retryCount) {
                this._gettingCount++
                hg.getFriendInfos({
                    uids: Number(hogame.config.uid),
                    success: (res: hg.IFriendInfo[]): void => {
                        this._listFriendInfo = []
                        this._gettingCount = 0
                        res.forEach((value: hg.IFriendInfo): void => {
                            this._dicFriendInfo[value.uid] = value
                            this._listFriendInfo.push(value)
                        })
                        this._listAllCallbackSuccess.forEach((value: gea.interfaces.base.ICallback): void => {
                            value.excute(...this._listFriendInfo)
                        })
                        this.clearDics(this._dicAllCallbackSuccessRecord, this._dicAllCallbackFailedRecord)
                        this._listAllCallbackSuccess.length = this._listAllCallbackFailed.length = 0
                    },
                    fail: (res: hg.IFriendError): void => {
                        if (this._retryDelay > 0) {
                            gea.timer.once(this._retryDelay, this.retryGetFromApp, this, res)
                        } else {
                            this.retryGetFromApp(res)
                        }
                    },
                })
            } else {
                gea.warn(`hg.getFriendInfos failed after ${this._gettingCount} times, failedCode: ${friendError.errCode}.`)
                this._gettingCount = 0
                this._listAllCallbackFailed.forEach((value: gea.interfaces.base.ICallback): void => {
                    value.excute(friendError)
                })
                this._listAllCallbackFailed.length = this._listAllCallbackSuccess.length = 0
            }
        }

        private clearDics(...dics: {}[]): void {
            dics.forEach((dic: {}): void => {
                Object.keys(dic).forEach((uuid: string): void => {
                    delete dic[uuid]
                })
            })
        }

        private defaultInfo({ uid,
            nick = uid,
            avatar = 'https://o-hk.ihago.net/ikxd/6727a572442261d5daa8ca3e012b441f/guest_1.png',
            type = hago.enums.friendType.hago,
            dist = 0,
            onlineStatus = Math.random() > 0.5 ? hago.enums.onlineStatus.offLine : hago.enums.onlineStatus.onLine,
            sex = Math.random() > 0.5 ? hago.enums.sex.female : hago.enums.sex.male,
            alias = hago.enums.constellation.aquarius,
        }): hg.IFriendInfo {

            return {
                uid: uid,
                nick: nick,
                avatar: avatar,
                type: type,
                dist: dist,
                onlineStatus: onlineStatus,
                sex: sex,
                alias: alias,
            }
        }
    }
    export const friendInfo: hogame.utils.IFriendInfoManager = new FriendInfoManager()
}
