/// <reference path="../UUID.ts" />

namespace gea.decorators.base {
    const mapSingleton: Map<string, boolean> = new Map()
    /**
     * 单例模式装饰器
     * @param constructor
     */
    export function singleton<T extends { new(...args: any[]): {} }>(singletonConstructor: T): T {
        return class extends singletonConstructor {
            constructor(...args: any[]) {
                super(...args)
                const uuid: string = gea.uuid(singletonConstructor)
                if (mapSingleton.has(uuid)) {
                    throw new Error(`${singletonConstructor.name} is a singleton class, please don't duplicate instantiate it`)
                } else {
                    mapSingleton.set(uuid, true)
                }
            }
        }
    }
}
