/// <reference path="./interfaces/IPoolManager.ts" />

namespace gea {
    class PoolManager implements interfaces.base.IPoolManager {
        private _mapPool: Map<string, Set<interfaces.base.IPoolObject>> = new Map

        borrow<T extends interfaces.base.IPoolObject>(poolClass: { prototype: T, new(): T }, ...args: any[]): T {
            const uuid: string = gea.uuid(poolClass)
            let pool: Set<interfaces.base.IPoolObject> = this._mapPool.get(uuid)
            if (pool == null) {
                pool = new Set()
                this._mapPool.set(uuid, pool)
            }
            let next = pool.values().next()

            let ins: T = next.value
            if (ins != null) {
                pool.delete(ins)
            } else {
                ins = new poolClass()
            }
            if (ins.callbackAfterBorrow) {
                ins.callbackAfterBorrow(...args)
            }
            return ins
        }

        restore(ins: interfaces.base.IPoolObject, ...args: any[]): void {
            if (!ins) {
                gea.error(`restore element is null, check your logic!`)
                return
            }
            if (!ins.callbackBeforeRestore || ins.callbackBeforeRestore(...args)) {
                let pool: Set<interfaces.base.IPoolObject> = this._mapPool.get(gea.uuid(ins.constructor))
                if (pool != null) {
                    // 放回到对象池
                    if (!pool.has(ins)) {
                        pool.add(ins)
                    } else {
                        gea.error('pool restore repeated, please check your logic!', JSON.stringify(ins))
                    }
                } else {
                    pool = new Set()
                    this._mapPool.set(gea.uuid(ins.constructor), pool)
                    pool.add(ins)
                }
            }
        }
    }

    export const pool: interfaces.base.IPoolManager = new PoolManager()
}
