/// <reference path="../../interfaces/IUI.ts" />
/// <reference path="../../../../../gea/gea-tween/src/tween/Enums.ts" />
/// <reference path="../../../../../gea/gea-tween/src/tween/interfaces/ITweener.ts" />

namespace gea.adapters.interfaces.ui {
    export interface IUIManager {
        /**
         * 视窗大小，游戏视图窗口
         */
        readonly viewPort: { width: number, height: number, halfWidth: number, halfHeight: number }
        /**
         * 模态ui遮罩
         */
        readonly nodeModal: cc.Node
        /**
         * 显示一个ui
         * @param uiClass 要显示的ui的class
         * @param option  额外参数
         * + tweener: 通过gea.tween.create创建
         * + args: 额外参数，会携带在callbackBeforeShow、callbackAfterShow中
         */
        show(uiClass: gea.interfaces.ui.IUIClass, option?: { tween?: { duration: number, from?: { [key: string]: number }, to?: { [key: string]: number }, option?: gea.interfaces.tween.ITweenOption }, args?: any[] }): IUIManager
        /**
         * 隐藏一个ui
         * @param uiClass 要显示的ui的class或者ui实例
         * @param option  额外参数
         * + tweener: 通过gea.tween.create创建
         * + args: 额外参数，会携带在callbackBeforeShow、callbackAfterShow中
         */
        hide(uiClass: gea.interfaces.ui.IUIClass | gea.adapters.abstracts.ui.UIBase, option?: { tween?: { duration: number, from?: { [key: string]: number }, to?: { [key: string]: number }, option?: gea.interfaces.tween.ITweenOption }, args?: any[] }): IUIManager
        /**
         * 隐藏所有ui
         */
        hideAll(excludeUIClass: gea.interfaces.ui.IUIClass[]): IUIManager
        /**
         * 判断某个ui是否正在显示
         * @param uiClass
         */
        isShowing(uiClass: gea.interfaces.ui.IUIClass): boolean
        /**
         * ui设置
         * @param config 设置
         * + modal，模态窗口黑色遮罩的设置
         */
        setup(config: {
            modal?: {
                tweenShow?: {
                    duration: number,
                    from?: { opacity: number },
                    to?: { opacity: number },
                    option?: gea.interfaces.tween.ITweenOption,
                } | {
                    duration: number,
                    from?: { opacity: number },
                    to?: { opacity: number },
                    option?: gea.interfaces.tween.ITweenOption,
                }[],
                tweenHide?: {
                    duration: number,
                    from?: { opacity: number },
                    to?: { opacity: number },
                    option?: gea.interfaces.tween.ITweenOption,
                } | {
                    duration: number,
                    from?: { opacity: number },
                    to?: { opacity: number },
                    option?: gea.interfaces.tween.ITweenOption,
                }[],
            },
        }): IUIManager
        /**
         * 针对某ui事件新增一个订阅者,订阅执行一次后关闭,或者off显式关闭
         * @param tag 标记
         * @param callback 回调函数--订阅者
         * @param scope 回调函数作用域
         * @param callbackArgs 回调参数
         * @see gea.events.ui
         */
        once(tag: any, callback: Function, scope: any, ...callbackArgs: any[]): IUIManager
        /**
         * 针对某ui事件新增一个订阅者
         * @param tag 标记
         * @param callback 回调函数--订阅者
         * @param scope 回调函数作用域
         * @param callbackArgs 回调参数
         * @see gea.events.ui
         */
        on(tag: any, callback: Function, scope: any, ...callbackArgs: any[]): IUIManager
        /**
         * 针对某ui事件新增一个订阅者
         * @param tag 标记
         * @param callbackLimite 回调次数限制,小于等于0表示不限制回调次数,default = 0,如果此参数不是一个数字,那么将把此参数作为callback参数的值使用
         * @param callback 回调函数--订阅者
         * @param scope 回调函数作用域
         * @param callbackArgs 回调参数
         * @see gea.events.ui
         */
        on(tag: any, callbackLimite: number, callback: Function, scope: any, ...callbackArgs: any[]): IUIManager
        /**
         * 移除一个订阅者
         * @param tag 标记
         * @param callback 回调函数
         * @param scope 回调函数作用域
         */
        off(tag: any, callback: Function, scope: any): IUIManager
        /**
         * 触发一个tag,通知所有的tag订阅者(执行回调函数)
         * @param tag 标记
         * @param args 附加回调参数
         */
        /**
         * 移除实例相关的所有订阅者
         * @param scope 实例本身(this)
         */
        offByScope(scope: any): IUIManager
    }
}
