/// <reference path="../../Enums.ts" />
/// <reference path="../../interfaces/IUI.ts" />
/// <reference path="../../../../../gea/gea-tween/src/tween/interfaces/ITweener.ts" />


namespace gea.adapters.abstracts.ui {
    const { ccclass, property } = cc._decorator
    @ccclass
    export abstract class UIBase extends cc.Component implements gea.interfaces.ui.IUI {
        /**
         * 模态UI
         */
        static get modal(): boolean {
            return this.DEFAULT_SETUP.modal
        }

        /**
         * 获取prefabUrl
         */
        static get prefabUrl(): string {
            throw new Error('please override in subclass!')
        }

        /**ui类型 */
        static get uiType(): gea.enums.ui.ui_type {
            throw new Error('please override in subClass!')
        }

        get customTweenShow(): gea.interfaces.tween.ITweener | Array<gea.interfaces.tween.ITweener> | undefined {
            return undefined
        }

        get customTweenHide(): gea.interfaces.tween.ITweener | Array<gea.interfaces.tween.ITweener> | undefined {
            return undefined
        }

        static get runTimeDynamicAsset(): { url: string, type?: typeof cc.Asset }[] {
            let listruntimeDynamicAsset: { url: string, type?: typeof cc.Asset }[] = this._mapRuntimeDynamicAsset.get(this.prefabUrl)
            if (listruntimeDynamicAsset == null) {
                listruntimeDynamicAsset = []
                this._mapRuntimeDynamicAsset.set(this.prefabUrl, listruntimeDynamicAsset)
            }
            return listruntimeDynamicAsset
        }
        @property({ type: cc.Node, tooltip: '阻止点击自动关闭的节点\n点击此节点范围以外的区域自动关闭UI\n若未设置，则该ui没有点击时自动关闭的逻辑' })
        get nodePreventTapClose(): cc.Node {
            return this._nodePreventTapClose
        }
        set nodePreventTapClose(value: cc.Node) {
            this._nodePreventTapClose = value
            if (CC_EDITOR) {
                if (this.getComponent(cc.Widget) == null) {
                    const widget: cc.Widget = this.addComponent(cc.Widget)
                    widget.isAlignLeft = widget.isAlignTop = widget.isAlignRight = widget.isAlignBottom = true
                    widget.alignMode = cc.Widget.AlignMode.ON_WINDOW_RESIZE
                    widget.left = widget.top = widget.right = widget.bottom = 0
                }
            }
        }
        @property({
            displayName: '自动释放UI资源',
            tooltip:
                `1.callbackAfterHide回调后自动释放ui自身以及引用的资源
                2.默认在关闭后会根据[释放延迟]自动释放其引用的资源
                `,
        })
        set autoRelease(value: boolean) {
            this._autoRelease = value
        }
        get autoRelease(): boolean {
            return this._autoRelease || this._multiInstance
        }
        @property({
            type: cc.Float,
            displayName: '延迟释放时间(单位:秒)', visible: function () { return this._autoRelease },
            tooltip:
                `1.callbackAfterHide回调后开始计时
                2.如果在延迟时间内又展示了UI,则取消释放
                3.默认为0秒,立即释放`,
        })
        set autoReleaseDelayTime(value: number) {
            this._autoReleaseDelayTime = value
        }
        get autoReleaseDelayTime(): number {
            return this._autoReleaseDelayTime
        }
        @property({
            displayName: '阻止穿透',
            tooltip: `
            1.此node的width和height范围的点击事件将被拦截不会穿透到下层
            2.如果想阻止全屏穿透,则给此ui加一个wediget并且适配到全屏即可
            `,
        })
        set blockEvents(value: boolean) {
            if (value) {
                if (this.node.getComponent(cc.BlockInputEvents) == null) {
                    this.node.addComponent(cc.BlockInputEvents)
                }
            } else {
                this.node.removeComponent(cc.BlockInputEvents)
            }
            this._blockEvents = value
        }
        get blockEvents(): boolean {
            return this._blockEvents
        }
        @property({
            displayName: '多实例UI',
            tooltip: `
            1.多实例UI表示显示的时候每次都重新创建一个,
            2.多实例UI会默认为自动释放
            3.多实例UI在关闭时传入要关闭的UI实例: gea.ui.hide(this, ...)
            `,
        })
        set multiInstance(value: boolean) {
            this._multiInstance = value
        }
        get multiInstance(): boolean {
            return this._multiInstance
        }
        /**默认配置信息 */
        protected static DEFAULT_SETUP: {
            modal?: boolean,
        } = {}
        private static _mapRuntimeDynamicAsset: Map<string, { url: string, type?: typeof cc.Asset }[]> = new Map()

        @property({
            type: cc.Asset, displayName: '依赖的资源列表',
            tooltip:
                `1.该列表内的资源会随着此ui一起被加载
                2.并非依赖资源,但希望随此ui一起加载的资源也可以拖到这个列表`,
        })
        preAssets: cc.Asset[] = []

        @property({ type: cc.Node })
        _nodePreventTapClose: cc.Node = null

        @property
        _autoRelease: boolean = true

        @property
        _autoReleaseDelayTime: number = 0

        @property
        _blockEvents: boolean = false

        @property
        _multiInstance: boolean = false

        constructor() {
            super()
            if (!CC_EDITOR) {
                cc.director.once(cc.Director.EVENT_AFTER_UPDATE, (): void => {
                    if (this.node && this._nodePreventTapClose) {
                        const worldPos: cc.Vec2 = this._nodePreventTapClose.parent.convertToWorldSpaceAR(this._nodePreventTapClose.getPosition())
                        const left: number = worldPos.x - this._nodePreventTapClose.width * this._nodePreventTapClose.anchorX
                        const top: number = worldPos.y + this.nodePreventTapClose.height * this._nodePreventTapClose.anchorY
                        const right: number = left + this._nodePreventTapClose.width
                        const bottom: number = top - this._nodePreventTapClose.height
                        this.node.on(cc.Node.EventType.TOUCH_END, (e: cc.Event.EventTouch): void => {
                            const touchX: number = e.touch.getLocationX()
                            const touchY: number = e.touch.getLocationY()
                            if (touchX < left || touchX > right || touchY < bottom || touchY > top) {
                                gea.ui.hide(<typeof UIBase>this.constructor)
                            }
                        })
                    }
                })
            }
        }

        static appendRunTimeDynamicAsset(...assets: { url: string, type?: typeof cc.Asset }[]): void {
            assets.forEach(value => {
                if (!cc.resources.get(value.url, value.type)) {
                    let listruntimeDynamicAsset: { url: string, type?: typeof cc.Asset }[] = this._mapRuntimeDynamicAsset.get(this.prefabUrl)
                    if (listruntimeDynamicAsset == null) {
                        listruntimeDynamicAsset = []
                        this._mapRuntimeDynamicAsset.set(this.prefabUrl, listruntimeDynamicAsset)
                    }
                    listruntimeDynamicAsset.push(value)
                }
            })
        }

        static clearRunTimeDynamicAsset(): void {
            const listruntimeDynamicAsset: { url: string, type?: typeof cc.Asset }[] = this._mapRuntimeDynamicAsset.get(this.prefabUrl)
            if (listruntimeDynamicAsset) {
                listruntimeDynamicAsset.length = 0
            }
        }

        /**
         * 设置
         * @param value
         */
        static setup(value: {
            modal?: boolean,
        }): void {
            this.DEFAULT_SETUP.modal = value.modal
        }

        /**
         * 添加到舞台前的回调/UI已经在显示中,再次调用show,也会回调
         * @param args
         */
        callbackBeforeShow(...args: any[]): void { }
        /**
         * 添加到舞台后的回调//UI已经在显示中,再次调用show,也会回调
         * @param args
         */
        callbackAfterShow(...args: any[]): void { }
        /**
         * 从舞台移除前的回调
         * @param args
         */
        callbackBeforeHide(...args: any[]): void { }
        /**
         * 从舞台移除后的回调
         * @param args
         */
        callbackAfterHide(...args: any[]): void { }
    }
}
