/// <reference path="../../../gea/gea-net/src/net/abstracts/NetBase.ts" />
/// <reference path="../../../gea/gea-base/src/base/Timer.ts" />
/// <reference path="./interfaces/IGmeNet.ts" />
/// <reference path="./GmeNetParser.ts" />
/// <reference path="./GmeNetHeartBeat.ts" />
/// <reference path="./interfaces/IGmeNetParser.ts" />

namespace gea {
    class GmeNet extends gea.abstracts.net.NetBase implements interfaces.net.IGmeNet {
        private _uid: string | number
        private _netParser: interfaces.net.IGmeNetParser
        private _heartBeat: interfaces.net.INetHeartBeat
        get uid(): string | number {
            return this._uid
        }
        get parser(): interfaces.net.IGmeNetParser {
            return this._netParser || (this._netParser = gea.utility.entity.getComponent(this, abstracts.net.NetParserBase, true))
        }
        get heartBeat(): interfaces.net.INetHeartBeat {
            return this._heartBeat || (this._heartBeat = gea.utility.entity.getComponent(this, abstracts.net.NetHeartBeatBase, true))
        }
        get connected(): boolean {
            return this._socket && this._socket.readyState === WebSocket.OPEN
        }
        private _uri: string
        get uri(): string {
            return this._uri
        }
        private _opts: {
            binaryType?: 'blob' | 'arraybuffer',
            protocols?: string | string[],
            reconnection?: boolean,
            reconnectionAttempts?: number,
            reconnectionDelay?: number,
            reconnectionDelayMax?: number,
            reconnectionDealyFunc?: (reconnectionAttempts: number, reconnectionDelay: number, reconnectionDelayMax: number) => number,
            timeout?: number,
            path?: string,
            query?: {},
        } = {
                binaryType: 'arraybuffer',
                reconnection: true,
                reconnectionAttempts: Infinity,
                reconnectionDelay: 1000,
                reconnectionDelayMax: 5000,
                timeout: 10000,
            }
        private _reconnectAttempts: number = 0
        private _reconnectionDealy: number = 0
        private _socket: WebSocket

        setup(uid: string | number, opts?: {
            reconnection?: boolean,
            reconnectionAttempts?: number,
            reconnectionDelay?: number,
            reconnectionDelayMax?: number,
            reconnectionDealyFunc?: (reconnectionAttempts: number, reconnectionDelay: number, reconnectionDelayMax: number) => number,
            timeout?: number,
        }): GmeNet {
            this._uid = uid
            if (opts) {
                Object.keys(opts).forEach((key: string): void => {
                    if (this._opts[key] != null) {
                        this._opts[key] = opts[key]
                    }
                })
            }
            return this
        }

        connect(uri: string, opts?: {
            binaryType?: 'blob' | 'arraybuffer',
            protocols?: string | string[],
            reconnection?: boolean,
            reconnectionAttempts?: number,
            reconnectionDelay?: number,
            reconnectionDelayMax?: number,
            reconnectionDealyFunc?: (reconnectionAttempts: number, reconnectionDelay: number, reconnectionDelayMax: number) => number,
            timeout?: number,
            path?: string,
            query?: {},
        }): void {
            this.disconnect()
            this._uri = uri
            if (opts != null) {
                Object.keys(opts).forEach((key: string): void => {
                    if (this._opts[key] != null) {
                        this._opts[key] = opts[key]
                    }
                })

                this._opts.reconnectionDelayMax = Math.max(this._opts.reconnectionDelay, this._opts.reconnectionDelayMax)
                this._uri += opts.path ? opts.path : ''
                if (opts.query != null) {
                    let queryContent: string = ''
                    Object.keys(opts.query).forEach((key: string): void => {
                        if (queryContent !== '') {
                            queryContent += '&' + key + '=' + opts.query[key]
                        } else {
                            queryContent += key + '=' + opts.query[key]
                        }
                    })
                    if (queryContent !== '') {
                        this._uri += '?' + queryContent
                    }
                }
            }
            this.doConnect()
        }

        disconnect(): void {
            if (this._socket != null) {
                this.deRegisterWsEvent()
                if (this._socket.readyState !== WebSocket.CLOSING && this._socket.readyState !== WebSocket.CLOSED) {
                    this._socket.close()
                }
                this._socket = null
                super.disconnect()
            }
        }

        send(netTag: string | number, data?: any, path?: string, roomId?: string): GmeNet {
            data = data || {}
            const result: gea.interfaces.net.INetParserEncodeResult = this.encode(netTag, data, path, roomId)
            if (this._socket != null) {
                if (this.connected) {
                    if (result.sendAble) {
                        this._socket.send(result.data)
                    }
                } else {
                    error('socket unconnected, sending -> ', netTag, JSON.stringify(data))
                }
            } else {
                error('soket is null, sending -> ', netTag, JSON.stringify(data))
            }
            return this
        }

        enterRoom(path: string, roomId?: string, msg?: any): void {
            gea.net.send('net.ihago.gme.srv.sidecar_gateway.GMEInternalEnterRoom', msg, path, roomId)
        }

        leaveRoom(path: string, msg?: any): void {
            gea.net.send('net.ihago.gme.srv.sidecar_gateway.GMEInternalLeaveRoom', msg, path)
        }

        createNew(name?: string): GmeNet {
            return gea.pool.borrow(GmeNet, name)
        }

        callbackBeforeRestore(): boolean {
            super.callbackBeforeRestore()
            this._opts.binaryType = 'arraybuffer'
            this._opts.protocols = null
            this._opts.reconnection = true
            this._opts.reconnectionAttempts = Infinity
            this._opts.reconnectionDealyFunc = null
            this._opts.reconnectionDelay = 1000
            this._opts.reconnectionDelayMax = 5000
            this._opts.timeout = 10000
            this._socket = null
            this._netParser = null
            this._heartBeat = null
            return true
        }

        private connectTimeout(): void {
            this.onWsEvent('conect timeout')
            this.attemptReconnect()
        }

        private attemptReconnect(): void {
            this.disconnect()
            if (this._opts.reconnection && (this._reconnectAttempts < this._opts.reconnectionAttempts)) {
                if (this._reconnectionDealy < this._opts.reconnectionDelayMax) {
                    if (this._opts.reconnectionDealyFunc != null) {
                        this._reconnectionDealy = Math.max(Math.min(this._opts.reconnectionDealyFunc(this._reconnectAttempts++, this._opts.reconnectionDelay, this._opts.reconnectionDelayMax), this._opts.reconnectionDelayMax), 0)
                    } else {
                        this._reconnectionDealy = Math.min(500 + this._reconnectionDealy, this._opts.reconnectionDelayMax)
                    }
                }
                if (this._reconnectionDealy > 0) {
                    gea.timer.once(this._reconnectionDealy, this.doReconnect, this)
                } else {
                    this.doReconnect()
                }
            } else {
                this.onNetEvent(events.net.connect_fail)
            }
        }

        private doReconnect(): void {
            this.onWsEvent('attemptReconnect', this._reconnectAttempts)
            this.doConnect()
        }

        private doConnect(): void {
            this.onWsEvent('connect server ' + this._uri)
            if (this._opts != null) {
                this._socket = new WebSocket(this._uri, this._opts.protocols)
                this._socket.binaryType = this._opts.binaryType || 'arraybuffer'
            } else {
                this._socket = new WebSocket(this._uri)
                this._socket.binaryType = 'arraybuffer'
            }
            this.registerWsEvent()
            if (this._opts.timeout > 0) {
                gea.timer.once(this._opts.timeout, this.connectTimeout, this)
            }
        }

        private deRegisterWsEvent(): void {
            this._socket.onopen = null
            this._socket.onerror = null
            this._socket.onclose = null
            this._socket.onmessage = null
            gea.timer.off(this.connectTimeout, this)
            gea.timer.off(this.doReconnect, this)
        }

        private registerWsEvent() {
            this._socket.onopen = (e: Event): void => {
                gea.timer.off(this.connectTimeout, this)
                this.onWsEvent('open', e)
                if (this._reconnectAttempts > 0) {
                    this.onNetEvent(events.net.reconnect, this._reconnectAttempts)
                }
                this._reconnectAttempts = 0
                this.onNetEvent(events.net.connect)
            }
            this._socket.onerror = (e: Event): void => {
                gea.timer.off(this.connectTimeout, this)
                this.onWsEvent('error', e)
                this.onNetEvent(events.net.disconnect)
                this.attemptReconnect()
            }
            this._socket.onclose = (e: CloseEvent): void => {
                gea.timer.off(this.connectTimeout, this)
                this.onWsEvent('close', e)
                this.onNetEvent(events.net.disconnect)
                this.attemptReconnect()
            }
            this._socket.onmessage = (e: MessageEvent): void => {
                // ArrayBuffer
                this.decode(e.data)
            }
        }
    }
    /**
     * 玩家网络实例
     */
    export const net: interfaces.net.IGmeNet = gea.pool.borrow(GmeNet)
}
