declare namespace hg {
    function reportData(data: {
        /**事件ID，每个事件ID唯一 */
        eventid: string,
        /**上报的自定义数据 */
        datas: {
            /**事件ID，每个事件ID唯一 */
            eventid: string,
            /**其他自定义参数 */
            [key: string]: number | string,
        }[],
        /**上报成功回调 */
        success: (res: { code: number, msg: string }) => void,
        /**上报失败回调 */
        fail: (res: { code: number, msg: string }) => void,
    })
}
