/// <reference path="../../../../gea-base/src/base/interfaces/IGea.ts" />
/// <reference path="../../../../gea-base/src/base/interfaces/ILog.ts" />
/// <reference path="../../../../gea-base/src/base/utility/Dispatcher.ts" />
/// <reference path="../../../../gea-base/src/base/Pool.ts" />
/// <reference path="../../../../gea-base/src/base/Gea.ts" />
/// <reference path="../../../../gea-base/src/base/Polling.ts" />
/// <reference path="../../../../gea-base/src/base/Log.ts" />
/// <reference path="../../../../gea-base/src/base/utility/Entity.ts" />
/// <reference path="../interfaces/INet.ts" />
/// <reference path="../interfaces/INetParser.ts" />
/// <reference path="../Event.ts" />

namespace gea.abstracts.net {
    let _netCount = -1
    export abstract class NetBase implements interfaces.net.INet {
        get parser(): interfaces.net.INetParser {
            throw new Error(`please override in subClass, and don't call 'super.parser'`)
        }
        get serverTime(): number {
            this.syncServerTime()
            return this._serverTime || gea.instance.localTime
        }

        get delayTime(): number {
            return this._delayTime
        }

        get connected(): boolean {
            throw new Error('please override in subclass!')
        }
        protected _reqForbiddenAll: boolean = false
        protected _dicReqForbidden: { [netTag: string]: boolean } = {}
        protected _resForbiddenAll: boolean = false
        protected _dicResForbidden: { [netTag: string]: boolean } = {}
        protected _name: string = 'NET'
        private _prevSyncTime: number = 0
        private _serverTime: number = NaN
        private _delayTime: number = 0

        createNew(name?: string): NetBase {
            throw new Error('please override in subclass!')
        }

        connect(uri: string, opts?: any) {
            throw new Error('please override in subclass!')
        }

        disconnect(): void {
            this.onNetEvent(gea.events.net.disconnect_self)
        }

        send(netTag: string | number, data?: any, ...args: any[]): NetBase {
            throw new Error('please override in subclass!')
        }

        updateServerTime(serverTime: number, delayTime: number, log: boolean = false): void {
            if (isNaN(delayTime) || delayTime < 0) {
                delayTime = 0
            }
            this._delayTime = delayTime
            if (!isNaN(this._serverTime)) {
                const diffTime = this.serverTime - serverTime
                if (diffTime > delayTime || diffTime < -delayTime) {
                    this._prevSyncTime = gea.instance.pastTime
                    this._serverTime = serverTime + delayTime
                }
                if (log) {
                    gea.info('[gea.net.updateServerTime] diffServerTime:', diffTime, 'delayTime:', delayTime)
                }
            } else {
                this._prevSyncTime = gea.instance.pastTime
                this._serverTime = serverTime + delayTime
                if (log) {
                    gea.info('[gea.net.updateServerTime] init:', this._serverTime, 'delayTime:', delayTime)
                }
            }
        }

        once(netTag: string | number, callback: Function, scope?: any, ...callbackArgs: any[]): NetBase {
            gea.utility.dispatcher.once(this, netTag, callback, scope, ...callbackArgs)
            return this
        }

        on(netTag: string | number, callbackLimite: number | Function, callback: Function, scope?: any, ...callbackArgs: any[]): NetBase {
            gea.utility.dispatcher.on(this, netTag, callbackLimite, callback, scope, ...callbackArgs)
            return this
        }

        off(netTag: string | number, callback: Function, scope?: any): NetBase {
            gea.utility.dispatcher.off(this, netTag, callback, scope)
            return this
        }

        oncePrior(netTag: string | number, callback: Function, scope?: any, ...callbackArgs: any[]): NetBase {
            gea.utility.dispatcher.oncePrior(this, netTag, callback, scope, ...callbackArgs)
            return this
        }

        onPrior(netTag: string | number, callbackLimite: number | Function, callback: Function, scope?: any, ...callbackArgs: any[]): NetBase {
            gea.utility.dispatcher.onPrior(this, netTag, callbackLimite, callback, scope, ...callbackArgs)
            return this
        }

        offByScope(scope: any): NetBase {
            gea.utility.dispatcher.offByScope(scope, this)
            return this
        }

        dispatch(tag: any, ...args: any[]): NetBase {
            gea.utility.dispatcher.dispatch(this, tag, ...args)
            return this
        }

        forbidReqLog(...netTags: (string | number)[]): NetBase {
            if (netTags.length > 0) {
                this._reqForbiddenAll = false
                netTags.forEach((netTag: string | number): void => {
                    this._dicReqForbidden[netTag] = true
                })
            } else {
                this._reqForbiddenAll = true
            }
            return this
        }

        forbidResLog(...netTags: (string | number)[]): NetBase {
            if (netTags.length > 0) {
                this._resForbiddenAll = false
                netTags.forEach((netTag: string | number): void => {
                    this._dicResForbidden[netTag] = true
                })
            } else {
                this._resForbiddenAll = true
            }
            return this
        }

        destroy(): void {
            gea.pool.restore(this)
        }

        callbackAfterBorrow(name?: string): void {
            if (name == null) {
                name = `NET${++_netCount > 0 ? _netCount : ''}`
            }
            this._name = name
            gea.instance.dispatch('gea.events.net.callbackAfterBorrow', this)
        }

        callbackBeforeRestore(): boolean {
            this.disconnect()
            gea.instance.dispatch('gea.events.net.callbackBeforeRestore', this)
            return true
        }

        protected decode(data: any): void {
            let result: gea.interfaces.net.INetParserDecodeResult
            try {
                result = this.parser.decode!(data)
            } catch (e) {
                gea.error('netParser decode error!', '\ndata:' + JSON.stringify(data), '\n' + e.stack)
                return
            }
            if (result) {
                if (result.log) {
                    this.logRes(result.msg, result.log)
                }
                this.dispatch(result.msg, result.data, ...result.args)
            }
        }

        protected encode(netTag: string | number, data: any, ...args: any[]): gea.interfaces.net.INetParserEncodeResult {
            let result: gea.interfaces.net.INetParserEncodeResult
            try {
                result = this.parser.encode!(netTag, data, ...args)
            } catch (e) {
                gea.error('netParser encode error', netTag, JSON.stringify(data))
                return { sendAble: false, msg: netTag, data: undefined, log: '' }
            }
            if (result.log) {
                this.logReq(netTag, result.log)
            }
            return result
        }

        protected onNetEvent(event: events.net, ...args: any[]): void {
            gea.info('[gea.net]' + event, ...args)
            this.dispatch(event, ...args)
        }

        protected onIoEvent(event: string, param?: any): void {
            gea.info('[socket.io]' + event, param ? 'param:' + JSON.stringify(param) : '')
        }

        protected onWsEvent(event: string, param?: any): void {
            gea.info('[gea.ws]' + event, param ? 'param:' + JSON.stringify(param) : '')
        }

        private syncServerTime(): void {
            const nowTime: number = gea.instance.pastTime
            if (nowTime > this._prevSyncTime) {
                this._serverTime += nowTime - this._prevSyncTime
                this._prevSyncTime = nowTime
            }
        }

        private logRes(netTag: string | number, content: string): void {
            if (this._dicResForbidden[netTag] == null && !this._resForbiddenAll) {
                gea.info(this._name, 'res', content)
            }
        }

        private logReq(netTag: string | number, content: string): void {
            if (this._dicReqForbidden[netTag] == null && !this._reqForbiddenAll) {
                gea.info(this._name, 'req', content)
            }
        }
    }
}
