namespace hogame {
    interface IPlayerInfo {
        uid?: string,
        name?: string,
        avatarurl?: string,
        opt?: string | {
            ai?: 1 | 0,
            level?: number,
            ai_info?: {
                uid?: string,
                nick?: string,
                sex?: 0 | 1,
            },
        },
        teamid?: string,
        sex?: 0 | 1,
        kv_sign?: string
    }
    interface IPostData {
        channelid?: string,
        gameid?: string,
        roomid?: string,
        player?: IPlayerInfo
    }
    interface IAiInfo {
        uid?: string,
        nick?: string,
        sex?: number
    }
    interface IOpt {
        ai?: number,
        level?: number,
        ai_info?: IAiInfo
    }
    interface IUrlParam {
        post_data?: IPostData,
        timestamp?: number,
        nonstr?: string,
        sign?: string
    }
    let urlParam: IUrlParam = {}
    let aiOpt: IOpt
    export function pkLogin(net: gea.interfaces.net.IGmeNet, post_data?: {
        channelid?: string
        roomid?: string,
        player?: {
            name?: string,
            avatarUrl?: string,
            teamid?: string,
            sex?: 0 | 1,
            kv_sign?: string,
            opt?: {
                ai?: 1 | 0,
                level?: number,
                ai_info?: {
                    uid?: string,
                    nick?: string,
                    sex?: 0 | 1,
                },
            },
        },
    }, invokeGameLoadResult: boolean = true): {
        channelid?: string
        roomid?: string,
        player?: {
            name?: string,
            avatarUrl?: string,
            teamid?: string,
            sex?: 0 | 1,
            kv_sign?: string,
            opt?: {
                ai?: 1 | 0,
                level?: number,
                ai_info?: {
                    uid?: string,
                    nick?: string,
                    sex?: 0 | 1,
                },
            },
        },
    } {
        let originPostData = ''
        if (window['hg'] == null) {
            urlParam.timestamp = gea.instance.localTime
            urlParam.nonstr = 'gecgtt92-bmj7-kb1k-w0d3-agvpmegp347f'
            urlParam.sign = 'c77621d59935c9acd0fa27e3c8cb7d7898fa40e5'
            urlParam.post_data = {
                roomid: gea.instance.localTime.toString(16),
                channelid: 'yy_haiou',
                gameid: hogame.config.gameId,
                player: {
                    uid: hogame.config.uid,
                    name: 'randomName' + (Math.random() * 10).toFixed(2),
                    avatarurl: 'https://o-hk.ihago.net/ikxd/3a79d0c04940f026a4d9758bcd6e0ab6/guest_3.png',
                    teamid: 'teamId1',
                    kv_sign: '',
                    sex: 0,
                    opt: '',
                },
            }
            if (post_data) {
                post_data.roomid && (urlParam.post_data.roomid = post_data.roomid)
                post_data.channelid && (urlParam.post_data.channelid = post_data.channelid)
                const playerInfo = post_data.player
                if (playerInfo) {
                    playerInfo.name && (urlParam.post_data.player.name = playerInfo.name)
                    playerInfo.avatarUrl && (urlParam.post_data.player.avatarurl = playerInfo.avatarUrl)
                    playerInfo.teamid && (urlParam.post_data.player.teamid = playerInfo.teamid)
                    playerInfo.kv_sign && (urlParam.post_data.player.kv_sign = playerInfo.kv_sign)
                    playerInfo.sex && (urlParam.post_data.player.sex = playerInfo.sex)
                    playerInfo.opt && (urlParam.post_data.player.opt = JSON.stringify(playerInfo.opt))
                }
            }
            originPostData = JSON.stringify(urlParam.post_data)

            reqHagoCode(`http://access-api-test-id.ihago.net/jssdk/hagoToken2code?token=${hogame.config.uid}&gameid=${hogame.config.gameId}`, (code: string): void => {
                connectServer(net, originPostData, code)
            })
        } else {
            if (invokeGameLoadResult) {
                hg.gameLoadResult({ code: 0 })
            }
            // wss://xyx-dk-test-id-954.ihago.net:443/huadongzhuoqiu/191cd7ce-2f4e-4cff-a0a6-2841e4e7f4ec/?post_data=%7B%22channelid%22%3A%22yy_haiou%22%2C%22gameid%22%3A%22huadongzhuoqiu%22%2C%22roomid%22%3A%22191cd7ce-2f4e-4cff-a0a6-2841e4e7f4ec%22%2C%22player%22%3A%7B%22uid%22%3A%22101535176%22%2C%22name%22%3A%22stqu2389%22%2C%22avatarurl%22%3A%22https%3A%2F%2Fo-hk.ihago.net%2Fikxd%2F3a79d0c04940f026a4d9758bcd6e0ab6%2Fguest_3.png%22%2C%22opt%22%3A%22%7B%5C%22ai%5C%22%3A1%2C%5C%22level%5C%22%3A4%2C%5C%22ai_info%5C%22%3A%7B%5C%22uid%5C%22%3A%5C%22900002045%5C%22%2C%5C%22nick%5C%22%3A%5C%22Muhammad%20Ghozi%20Setiawan%5C%22%2C%5C%22sex%5C%22%3A1%7D%7D%22%2C%22teamid%22%3A%22%22%2C%22sex%22%3A0%2C%22kv_sign%22%3A%22w88M3QEOikPF5cnR07_LWKgBo6OzED5e%22%7D%7D×tamp=1573723240&nonstr=gecgtt92-bmj7-kb1k-w0d3-agvpmegp347f&sign=c77621d59935c9acd0fa27e3c8cb7d7898fa40e5
            const matchupUrl: string = hg.getMatchupUrl()
            const matchupInfo: hg.IMatchupInfo = hg.getMatchupInfo()
            const listUrlSplit: string[] = matchupUrl.split('?')
            const listParam: string[] = listUrlSplit[1].split('&')
            let listParamValue: string[]
            listParam.forEach((value: string): void => {
                listParamValue = value.split('=')
                if (listParamValue[0] === 'post_data') {
                    originPostData = listParamValue[1]
                    urlParam[listParamValue[0]] = JSON.parse(decodeURIComponent(listParamValue[1]))
                } else {
                    urlParam[listParamValue[0]] = decodeURIComponent(listParamValue[1])
                }
            })
            gea.info('matchupUrl:', matchupUrl)
            gea.info('matchupInfo:', JSON.stringify(matchupInfo))
            hogame.config['_url'] = listUrlSplit[0].split(`/${matchupInfo.gameid}`)[0]

            hg.login({
                success(res: hg.ILoginSuccess): void {
                    connectServer(net, originPostData, res.code)
                },
                fail(): void {
                    gea.error('hg.login 获取code失败，退出游戏')
                    hg.exitMiniProgram({})
                },
            })
        }
        // @ts-ignore
        hogame.config._roomId = urlParam.post_data.roomid
        // @ts-ignore
        // hogame.config._gameId = urlParam.post_data.gameid
        if (urlParam.post_data.player.opt) {
            urlParam.post_data.player.opt = JSON.parse(<string>urlParam.post_data.player.opt)
        } else {
            urlParam.post_data.player.opt = {}
        }
        // @ts-ignore
        return urlParam.post_data
    }

    function reqHagoCode(url: string, callback: Function): void {
        gea.info(`开始请求code: ${url}`)
        const xhr: XMLHttpRequest = new XMLHttpRequest()
        // 这个地址如果token字段是非数字则取不到值
        xhr.open('get', url)
        xhr.onreadystatechange = (): void => {
            if (xhr.readyState === XMLHttpRequest.DONE) {
                if (xhr.status >= 200 && xhr.status <= 299) {
                    let result: { code: string, errcode: number }
                    try {
                        result = JSON.parse(xhr.responseText)
                        if (result.errcode !== 0) {
                            gea.warn(`reqHagoCode result:${xhr.responseText}`)
                            gea.error(`code请求结果有误,请将'uid'改短一点，且保证'uid'转成数字后不为'0'`)
                            return
                        }
                    } catch (e) {
                        gea.error(`code请求结果发生错误: ${xhr.responseText}`)
                        return
                    }
                    callback(result.code)
                }
            }
        }
        xhr.onerror = (): void => {
            gea.error(`code请求发生错误,请刷新重试`)
        }
        xhr.ontimeout = (): void => {
            gea.error(`code请求超时,开始重试`)
            reqHagoCode(url, callback)
        }
        xhr.send()
    }

    function connectServer(net: gea.interfaces.net.IGmeNet, originPostData: string, code: string): void {
        net.connect(hogame.config.url,
            {
                path: '/' + urlParam.post_data.gameid + '/' + urlParam.post_data.roomid + '/',
                query: {
                    post_data: originPostData,
                    timestamp: urlParam.timestamp,
                    nonstr: urlParam.nonstr,
                    sign: urlParam.sign,
                    code: code,
                    pingInterval: net.heartBeat.interval() / 1000,
                    pingTimeout: net.heartBeat.timeoutCountLimit() * (net.heartBeat.interval() / 1000),
                },
            })
    }
}
