namespace gea {
    let UUID: number = 0
    /**
     * 获取一个对象的uuid
     * @params target 任意对象,若为数字或者字符串则直接返回字符串格式
     * @params scope 作用域,若为数字或者字符串则忽略
     */
    export function uuid(target: any, scope?: any): string {
        if (target == null) {
            throw new Error('target is null')
        }
        if (target.constructor === String || target.constructor === Number) {
            return target as string
        }
        if (target['gea.uuid'] == null) {
            UUID++
            Object.defineProperty(target, 'gea.uuid', {
                value: 'gea.uuid' + UUID,
                writable: false,
                configurable: false,
                enumerable: false,
            })
        }
        if (scope != null && scope.constructor !== String && scope.constructor !== Number) {
            if (scope['gea.uuid'] == null) {
                UUID++
                Object.defineProperty(scope, 'gea.uuid', {
                    value: 'gea.uuid' + UUID,
                    writable: false,
                    configurable: false,
                    enumerable: false,
                })
            }
            return scope['gea.uuid'] + '_' + target['gea.uuid']
        }
        return target['gea.uuid']
    }
}
