
/// <reference path="../Hago.ts" />

declare namespace hg {
    interface IKVData {
        readonly key: string
        readonly value: string
    }
    interface IUserGameData {
        readonly openid: string
        readonly nickname: string
        readonly avatarUrl: string
        readonly KVDataList: Array<IKVData>
    }
    interface IAIUser {
        readonly openid: string
        readonly sex: hago.enums.sex
        readonly nickName: string
        readonly avatarUrl: string
    }
    /**
     * 拉取当前用户所有同玩好友的托管数据
     * @see http://kxd_3rd.kxd-pages.yy.com/kxd_3rd_ly/zh/opendata/getFriendCloudStorage.html
     */
    function getFriendCloudStorage(opt: { keyList: Array<string>, success?: (res: { data: Array<hg.IUserGameData> }) => void, fail?: () => void, complete?: () => void }): void
    /**
     * 取当前用户托管数据当中对应 key 的数据
     * @see http://kxd_3rd.kxd-pages.yy.com/kxd_3rd_ly/zh/opendata/getUserCloudStorage.html
     */
    function getUserCloudStorage(opt: { keyList: Array<string>, success?: (res: { KVDataList: Array<IKVData> }) => void, fail?: () => void, complete?: () => void }): void
    /**
     * 删除用户托管数据当中对应 key 的数据
     * @see http://kxd_3rd.kxd-pages.yy.com/kxd_3rd_ly/zh/opendata/removeUserCloudStorage.html
     */
    function removeUserCloudStorage(opt: { keyList: Array<string>, success?: (jsonStr: string) => void, fail?: () => void, complete?: () => void }): void
    /**
     * 对用户托管数据进行写数据操作。允许同时写多组 KV 数据
     *
     * 1.每个openid所标识的用户在每个游戏上托管的数据不能超过128个key-value对
     *
     * 2.上报的key-value列表当中每一项的key+value长度都不能超过1K(1024)字节
     *
     * 3.上报的key-value列表当中每一个key长度都不能超过128字节
     * @see http://kxd_3rd.kxd-pages.yy.com/kxd_3rd_ly/zh/opendata/setUserCloudStorage.html
     */
    function setUserCloudStorage(opt: { KVDataList: Array<{ key: string, vlaue: string }>, success?: (jsonStr: string) => void, fail?: () => void, complete?: () => void }): void
    /**
     * 获取AI用户信息列表
     * @see http://kxd_3rd.kxd-pages.yy.com/kxd_3rd_ly/zh/opendata/getAIUser.html
     */
    function getAIUser(opt: { num: number, success?: (jsonStr: string) => void, fail?: () => void, complete?: () => void }): void
}
