/// <reference path="../../../gea/gea-net/src/net/abstracts/NetHeartBeatBase.ts" />
/// <reference path="./interfaces/IGmeNet.ts" />
/// <reference path="../../../gea/gea-base/src/base/utility/Entity.ts" />
/// <reference path="../../../gea/gea-net/src/net/Event.ts" />

namespace gea {
    const MESSAGE_PING: string = 'reserved.gateway.ping'
    const MESSAGE_PONG: string = 'reserved.gateway.pong'
    class NetHeartBeat extends gea.abstracts.net.NetHeartBeatBase {
        callbackAfterBorrow(net: gea.interfaces.net.IGmeNet): void {
            this._entity = net
            this._entity.on(MESSAGE_PONG, this.pong, this)
            this.startupEvent(events.net.connect)
        }

        destroy(): void {
            super.destroy()
            gea.pool.restore(this)
        }

        protected ping(): void {
            this._entity.send(MESSAGE_PING, null, MESSAGE_PING, '')
        }

        protected pong(res: any, downStream: any): void {
            super.pong()
            // 最后一个参数打开就打印时间差
            this._entity.updateServerTime(Number(downStream.header.timestamp), (gea.instance.pastTime - this._listHeartBeatClientTime.shift()) * 0.5, this._printserverDiffTime)
        }
    }
    gea.instance
        .on('gea.events.net.callbackAfterBorrow', (net: gea.interfaces.net.IGmeNet): void => {
            gea.utility.entity.addComponent(net, gea.pool.borrow(NetHeartBeat, net))
        }, window)
        .on('gea.events.net.callbackBeforeRestore', (net: gea.interfaces.net.IGmeNet): void => {
            gea.utility.entity.removeComponent(net, NetHeartBeat).destroy()
        }, window)

    if (gea.net) {
        gea.utility.entity.addComponent(gea.net, gea.pool.borrow(NetHeartBeat, gea.net))
    }
}
