/// <reference path="../../../../gea/gea-base/src/base/Log.ts" />
/// <reference path="../../../../gea/gea-base/src/base/Timer.ts" />

namespace hago.report {
    const MAP_REPORT_DATA: Map<any, any> = new Map()
    let EVENT_ID: string = '20190429'

    /**
     * 设置时间ID，默认事件ID：'20190429'
     * @param value
     */
    export function eventid(value: string): void {
        EVENT_ID = value
    }
    /**
     * 上报自定义数据，失败之后会延迟500ms继续上报，尽量保证上报成功
     * @param datas
     */
    export function reportData(...datas: { eventid: string, [key: string]: number | string }[]): void {
        if (window['hg']) {
            if (hg.reportData) {
                const data = {
                    eventid: EVENT_ID, datas: datas,
                    success: (): void => {
                        MAP_REPORT_DATA.delete(data)
                    },
                    fail: (res: { code: number, msg: string }): void => {
                        gea.warn(`hg.reportData failed! reason: ${JSON.stringify(res || {})}`)
                        gea.timer.once(500, (): void => {
                            gea.info(`hg.reportData retry: ${JSON.stringify(data)}`)
                            hg.reportData(data)
                        }, this)
                    },
                }
                MAP_REPORT_DATA.set(data, data)
                hg.reportData(data)
            } else {
                gea.warn('当前版本不支持 上报自定义数据接口')
            }
        } else {
            gea.info(`hg.reportData: ${JSON.stringify(datas)}`)
        }
    }
}
