namespace hogame {
    /**
     * 登录游戏
     * @param net 要登录的网络实例
     * @param invokeGameLoadResult 是否调用`hg.gameLoadResult`
     * @param query query参数，默认为空
     */
    export function login(net: gea.interfaces.net.IGmeNet, invokeGameLoadResult: boolean = true, query: { [key: string]: string | number } = {}): void {
        query.uid = net.uid
        query.pingInterval = net.heartBeat.interval() / 1000
        query.pingTimeout = net.heartBeat.timeoutCountLimit() * query.pingInterval
        if (query.code) {
            gea.warn(`query内的code字段用于本地登录时作验证用的，一般不要自己传入，除非你确定传入的是正确的值，不然连接不了服务器`)
            connectServer(net, query)
        } else {
            if (window['hg']) {
                if (invokeGameLoadResult) {
                    hg.gameLoadResult({ code: 0 })
                }
                hg.login({
                    success(res: hg.ILoginSuccess): void {
                        query.code = res.code
                        connectServer(net, query)
                    },
                    fail(): void {
                        gea.error('hg.login 获取code失败，退出游戏')
                        hg.exitMiniProgram({})
                    },
                })
            } else {
                reqHagoCode(`http://access-api-test-id.ihago.net/jssdk/hagoToken2code?token=${hogame.config.uid}&gameid=${hogame.config.gameId}`, net, query)
            }
        }
    }

    function reqHagoCode(url: string, net: gea.interfaces.net.IGmeNet, query: { [key: string]: string | number }): void {
        gea.info(`开始请求code: ${url}`)
        const xhr: XMLHttpRequest = new XMLHttpRequest()
        // 这个地址如果token字段是非数字则取不到值
        xhr.open('get', url)
        xhr.onreadystatechange = (): void => {
            if (xhr.readyState === XMLHttpRequest.DONE) {
                if (xhr.status >= 200 && xhr.status <= 299) {
                    let result: { code: string, errcode: number }
                    try {
                        result = JSON.parse(xhr.responseText)
                        if (result.errcode !== 0) {
                            gea.warn(`reqHagoCode result:${xhr.responseText}`)
                            gea.error(`code请求结果有误,请将'uid'改短一点，且保证'uid'转成数字后不为'0'`)
                            return
                        }
                    } catch (e) {
                        gea.error(`code请求结果发生错误: ${xhr.responseText}`)
                        return
                    }
                    query.code = result.code
                    connectServer(net, query)
                }
            }
        }
        xhr.onerror = (): void => {
            gea.error(`code请求发生错误,请刷新重试`)
        }
        xhr.ontimeout = (): void => {
            gea.error(`code请求超时,开始重试`)
            reqHagoCode(url, net, query)
        }
        xhr.send()
    }

    function connectServer(net: gea.interfaces.net.IGmeNet, query: { [key: string]: string | number }): void {
        query.uid = net.uid
        if (window['hg']) {
            let subModuleUrl: string = hg.getSubModuleUrlSync({ id: 0 }).url
            gea.info(`子模块url: ${subModuleUrl}`)
            if (!subModuleUrl) {
                gea.warn(`子模块url获取失败，请联系服务器或者平台，确认是否已经发布到当前环境`)
                return
            }
            let splitIndex: number = subModuleUrl.lastIndexOf('/')
            if (splitIndex === subModuleUrl.length - 1) {
                subModuleUrl = subModuleUrl.slice(0, splitIndex)
                splitIndex = subModuleUrl.lastIndexOf('/')
            }

            // @ts-ignore
            if (window.__appointUrl__) {// 切换新的URL，否则会被覆盖回去
                // @ts-ignore
                console.log(' window.__appointUrl__:', window.__appointUrl__, subModuleUrl)
            }
            // @ts-ignore
            hogame.config._url = window.__appointUrl__ || subModuleUrl.slice(0, splitIndex)
            // @ts-ignore
            // hogame.config._gameId = subModuleUrl.slice(splitIndex + 1)
        }

        net.connect(hogame.config.url, {
            path: `/${hogame.config.gameId}/${gea.instance.localTime.toString(16)+ '_' + hogame.config.uid}/`,
            query: query,
        })
    }
}
