/// <reference path="./interfaces/ICallback.ts" />
/// <reference path="./interfaces/IPoolObject.ts" />
/// <reference path="./Log.ts" />
/// <reference path="./Pool.ts" />
/// <reference path="./UUID.ts" />

namespace gea {
    class Callback implements interfaces.base.ICallback, interfaces.base.IPoolObject {
        private _callback: Function
        private _scope: any
        private _callbackArgs: any[]
        private _callbackLimite: number
        private _mustRestoreAfterExcute: boolean = false
        private _excuting: boolean = false

        get discriminator(): gea.discriminator.interfaces.callback {
            return gea.discriminator.interfaces.callback
        }

        get lastTime(): number {
            return this._callbackLimite || Infinity
        }

        callbackLimite(value: number): Callback
        callbackLimite(): number
        callbackLimite(value?: number): Callback | number {
            if (value == null) {
                return this._callbackLimite
            }
            if (isNaN(value)) {
                gea.warn('value must be a number')
                return this
            } else if (value <= 0) {
                value = Infinity
            }
            if (this._mustRestoreAfterExcute) {
                this._mustRestoreAfterExcute = false
                this._callbackLimite += value
            } else if (this._excuting) {
                this._callbackLimite = value + 1
            } else {
                this._callbackLimite = value
            }
            return this
        }

        args(...callbackArgs: any[]): Callback {
            this._callbackArgs = callbackArgs
            return this
        }

        excute(...extraArgs: any[]): Callback {
            if (this._callback != null) {
                this._excuting = true
                if (--this._callbackLimite === 0) {
                    this._mustRestoreAfterExcute = true
                }
                this._callback.call(this._scope, ...this._callbackArgs, ...extraArgs)
                this._excuting = false
                if (this._mustRestoreAfterExcute) {
                    this._mustRestoreAfterExcute = false
                    gea.pool.restore(this)
                }
            } else {
                error('callback is null, but some where excute again!')
            }
            return this
        }

        restore(): void {
            gea.log('callback restore', gea.uuid(this))
        }

        callbackAfterBorrow(callback: Function, scope: any): void {
            if (callback == null) {
                throw new Error(`$'callback' can't be null!`)
            }
            this._callback = callback
            this._scope = scope
            this._callbackLimite = 0
        }

        callbackBeforeRestore(): boolean {
            if (!this._mustRestoreAfterExcute && !this._excuting) {
                this._callback = null
                this._scope = null
                this._callbackArgs = null
                return true
            }
            return false
        }

        destroy(...args: any[]): void {
            if (this._callback != null) {
                gea.pool.restore(this, ...args)
            }
        }
    }
    /**
     * 获取一个经过封装的回调函数
     * @param callback 回调函数
     * @param scope 回调函数作用于
     * @param callbackLimite 回调函数回调次数限制,0为不限制回调次数
     * @param callbackArgs 回调函数参数
     * @see gea.interfaces.base.ICallback
     */
    export function callback(callback: Function, scope: any, ...callbackArgs: any[]): interfaces.base.ICallback {
        return gea.pool.borrow(Callback, callback, scope).args(...callbackArgs)
    }
}
