/// <reference path="./interfaces/ITimer.ts" />
/// <reference path="./interfaces/IPoolObject.ts" />

/// <reference path="./Gea.ts" />
/// <reference path="./Polling.ts" />
/// <reference path="./Event.ts" />

namespace gea {
    let _nowTimestamp: number = gea.instance.pastTime
    let _prevTimestamp: number = _nowTimestamp
    let _dicTimerCallback: Object = {}

    class TimerCallback implements interfaces.base.IPoolObject {
        get callback(): interfaces.base.ICallback {
            return this._callback
        }

        private _callback: interfaces.base.ICallback
        private _nextCallbackTime: number
        private _callbackRate: number

        excute(uuid: string): void {
            const diff: number = _nowTimestamp - this._nextCallbackTime
            if (diff >= 0) {
                this._callback.excute()
                if (this._callback != null) {
                    if (this._callback.callbackLimite() > 0) {
                        // 延时补偿,不补偿所有丢失的时间,只补偿单帧的时间差异
                        this._nextCallbackTime = Math.max(this._callbackRate + _nowTimestamp - diff, _nowTimestamp)
                    } else {
                        this._callback = null
                        delete _dicTimerCallback[uuid]
                        gea.pool.restore(this)
                    }
                } else {
                    delete _dicTimerCallback[uuid]
                }
            }
        }

        resetNextCallbackTime(): void {
            this._nextCallbackTime = gea.instance.pastTime + this._callbackRate
        }

        callbackAfterBorrow(interval: number, callback: interfaces.base.ICallback): void {
            this._callback = callback
            this._callbackRate = interval
            this._nextCallbackTime = gea.instance.pastTime + interval
        }

        callbackBeforeRestore(): boolean {
            if (this._callback !== null) {
                this._callback.destroy()
            }
            this._callback = null
            return true
        }
    }

    class Timer implements interfaces.base.ITimer {
        constructor() {
            gea.polling.on(this.enterFrame, this)
        }
        once(interval: number, callback: Function, scope: any, ...callbackArgs: any[]): Timer {
            let uuid: string = gea.uuid(callback, scope)
            let timerCallback: TimerCallback = _dicTimerCallback[uuid]
            if (timerCallback == null) {
                timerCallback = gea.pool.borrow(TimerCallback, interval, gea.callback(callback, scope, ...callbackArgs).callbackLimite(1))
                _dicTimerCallback[uuid] = timerCallback
            } else {
                timerCallback.callback.args(...callbackArgs).callbackLimite(1)
            }
            return this
        }
        on(interval: number, callbackLimite: number | Function, callback: Function, scope: any, ...callbackArgs: any[]): Timer {
            if (callbackLimite.constructor !== Number) {
                if (scope != null || callbackArgs.length > 0) {
                    callbackArgs.unshift(scope)
                }
                scope = callback
                callback = <Function>callbackLimite
                callbackLimite = 0
            }
            let uuid: string = gea.uuid(callback, scope)
            let timerCallback: TimerCallback = _dicTimerCallback[uuid]
            if (timerCallback == null) {
                timerCallback = gea.pool.borrow(TimerCallback, interval, gea.callback.apply(gea, [callback, scope].concat(callbackArgs)).callbackLimite(<number>callbackLimite))
                _dicTimerCallback[uuid] = timerCallback
            } else {
                timerCallback.callback.args(...callbackArgs).callbackLimite(<number>callbackLimite)
            }
            return this
        }

        off(callback: Function, scope: any): Timer {
            let uuid: string = gea.uuid(callback, scope)
            let timerCallback: TimerCallback = _dicTimerCallback[uuid]
            if (timerCallback != null) {
                gea.pool.restore(timerCallback)
                delete _dicTimerCallback[uuid]
            }
            return this
        }

        offByScope(scope: any): Timer {
            const uuid: string = gea.uuid(scope)
            Object.keys(_dicTimerCallback).forEach(key => {
                if (key.split('_')[0] === uuid) {
                    gea.pool.restore(_dicTimerCallback[key])
                    delete _dicTimerCallback[key]
                }
            })
            return this
        }

        private enterFrame(): void {
            _nowTimestamp = gea.instance.pastTime
            const diffTime: number = _nowTimestamp - _prevTimestamp
            _prevTimestamp = _nowTimestamp
            if (diffTime > 0) {
                let uuid: string
                let timerCallback: TimerCallback
                for (uuid in _dicTimerCallback) {
                    timerCallback = _dicTimerCallback[uuid]
                    timerCallback.excute(uuid)
                }
            } else if (diffTime < 0) {
                gea.error('localTime reduced!', diffTime)
                let uuid: string
                let timerCallback: TimerCallback
                for (uuid in _dicTimerCallback) {
                    timerCallback = _dicTimerCallback[uuid]
                    timerCallback.resetNextCallbackTime()
                }
                gea.instance.dispatch(gea.events.base.localtime_reduced, diffTime)
            }
        }
    }

    export const timer: interfaces.base.ITimer = new Timer()
}
