
namespace gea {
    let _prefix: string
    export function log(...args: any[]): void {
        _prefix == null ? console.log(...args) : console.log(_prefix, ...args)
    }
    export function info(...args: any[]): void {
        _prefix == null ? console.info(...args) : console.info(_prefix, ...args)
    }
    export function warn(...args: any[]): void {
        _prefix == null ? console.warn(...args) : console.warn(_prefix, ...args)
    }
    export function error(...args: any[]): void {
        _prefix == null ? console.error(...args) : console.error(_prefix, ...args)
    }
    /**
     * 设置Log前缀
     * @param prefix
     */
    export function setLogPrefix(prefix: string): void {
        _prefix = prefix
    }
}
