/// <reference path="../../../../gea-base/src/base/interfaces/IDestroyAble.ts" />

namespace gea.interfaces.net {
    /**
     * 网络解析器编码结果
     */
    export interface INetParserEncodeResult {
        /**是否可以发送消息 */
        sendAble: boolean
        /**消息key */
        msg: string | number,
        /**发送给服务器的数据 */
        data: any,
        /**
         * 默认日志
         * + 网络实例会在发送消息前将日志打印出来
         * + 如果这个值是空的，则不打印
         */
        log: any
    }
    /**
     * 网络解析器解码结果
     */
    export interface INetParserDecodeResult {
        /**消息解析耗时 */
        decodeTime: number
        /**消息key */
        msg: string | number,
        /**
         * 收到的服务器返回的数据
         * + 解析后的`js对象`
         * + 网络实例会把这个`js对象`发布出去，监听了`msg`的地方会收到
         */
        data: any,
        /**
         * 默认日志
         * + 网络实例在消息解析后会将日志打印出来
         * + 如果这个值是空的，则不打印
         */
        log: any,
        /**额外发布的通知数据，服务器返回的当前消息内容会首先包含在数据中 */
        args: any[]
    }
    /**
     * 网络解析器
     */
    export interface INetParser {
        /**
         * 编码函数
         * @param netTag 编码tag,一般用作关系映射
         * @param sendData 被编码对象
         * @param type
         * @returns INetParserEncodeResult
         */
        encode(netTag: string | number, sendData: any, ...args: any[]): INetParserEncodeResult
        /**
         * 解码函数
         * @param recieveData
         * @param type
         * @returns INetParserDecodeResult
         */
        decode(recieveData: any, ...args: any[]): INetParserDecodeResult
        /**
         * 设置消息编码解码和路径映射
         * @param mapping
         * @ignore
         */
        setMapping(mapping: any): INetParser
        /**
         * 设置自定义encode日志回调
         * @param callback
         */
        setEncodeLogGenerator?(callback: (opt: any) => any): INetParser
        /**
         * 设置自定义decode日志回调
         * @param callback
         */
        setDecodeLogGenerator?(callback: (opt: any) => any): INetParser
    }
}
