/// <reference path="../interfaces/INetHeartBeat.ts" />
/// <reference path="../interfaces/INet.ts" />
/// <reference path="../../../../gea-base/src/base/Timer.ts" />
/// <reference path="../Event.ts" />

namespace gea.abstracts.net {
    export abstract class NetHeartBeatBase implements interfaces.net.INetHeartBeat {
        protected _entity: interfaces.net.INet | undefined
        protected _timeoutCountLimit: number = Infinity
        protected _pingRate: number = 5000
        protected _pingStartEvent: string | number = ''
        protected _listHeartBeatClientTime: number[] = []
        protected _printserverDiffTime: boolean = false
        private _running: boolean = false
        private _timeoutCount: number = 0
        timeoutCountLimit(): number
        timeoutCountLimit(value: number): interfaces.net.INetHeartBeat
        timeoutCountLimit(value?: number): unknown {
            if (value && !isNaN(value)) {
                if (this._timeoutCountLimit !== value) {
                    this._timeoutCountLimit = value
                }
                return this
            }
            return this._timeoutCountLimit
        }
        interval(): number
        interval(value: number): interfaces.net.INetHeartBeat
        interval(value?: number): unknown {
            if (value && !isNaN(value)) {
                if (this._pingRate !== value) {
                    this._pingRate = value
                    if (this._running) {
                        this.stopPing()
                        this.startPing()
                    }
                }
                return this
            }
            return this._pingRate
        }
        startupEvent(value: string | number, immediately: boolean = false): interfaces.net.INetHeartBeat {
            if (value !== this._pingStartEvent) {
                if (this._pingStartEvent) {
                    this._entity!.off(this._pingStartEvent, this.startPing, this)
                }
                this._pingStartEvent = value
                this._entity!.on(this._pingStartEvent, this.startPing, this)
                if (immediately) {
                    this.startPing()
                }
            }
            return this
        }

        printServerDiffTime(value: boolean): interfaces.net.INetHeartBeat {
            this._printserverDiffTime = value
            return this
        }

        destroy(): void {
            this.stopPing()
            this._listHeartBeatClientTime.length = 0
            if (this._entity !== undefined) {
                this._entity.offByScope(this)
                this._entity = undefined
            }
        }

        protected ping(): void {
            throw new Error('please override in subClass')
        }

        protected pong(...args: any[]): void {
            this._timeoutCount = 0
        }

        /**
         * 启动ping
         */
        private startPing(): void {
            this._listHeartBeatClientTime.length = 0
            this._timeoutCount = 0
            if (!this._running) {
                this._running = true
                gea.timer.off(this.pingCount, this)
                gea.timer.on(this._pingRate, this.pingCount, this)
                this.pingCount()
            }
        }

        private stopPing(): void {
            this._running = false
            gea.timer.off(this.pingCount, this)
        }

        /**
         * ping计数
         */
        private pingCount(): void {
            if (++this._timeoutCount <= this._timeoutCountLimit) {
                this._listHeartBeatClientTime.push(gea.instance.pastTime)
                this.ping()
            } else {
                this.stopPing()
                this._entity!.dispatch(events.net.heart_beat_timeout)
            }
        }
    }
}
