declare namespace hg {
    /**
    * 最小化语音房游戏
    * @see http://kxd_3rd.kxd-pages.yy.com/kxd_3rd_ly/zh/life/miniMizeWindow.html
    */
    function miniMizeWindow(): void
    /**
      * 打开礼物面板
      * @see https://kxd-gitlab.yy.com/kxd_3rd/hago_doc/blob/master/zh/room/room.md
      */
    function roomOpenPresentPanel(): void
    /**
    * 发送本地公屏消息   本地公屏，没有发出去，频道内其他人看不到. uid(发送者uid)=0,使用系统消息
    * @see https://kxd-gitlab.yy.com/kxd_3rd/hago_doc/blob/master/zh/room/room.md
    */
    function roomSendChat(opt: { uid?: number, content?: string }): void

    /**
     * 游戏通知金币变化
     * @param callback
     * @see https://kxd-gitlab.yy.com/kxd_3rd/hago_doc/blob/master/zh/room/room.md
     */
    function roomListenCoinChange(callback: () => void): void
    /**
     * 打开一个URL
     * @param opt
     * @see https://git.yy.com/midwares/gameplatform/hago-game-sdk/blob/master/sdk-hago%E6%8E%A5%E5%8F%A3.md
     */
    function roomOpenUrl(opt: { url?: string }): void
    /**
     * 显示/隐藏悬浮窗拖动区域
     * @see https://git.yy.com/midwares/gameplatform/hago-game-sdk/blob/master/sdk-hago%E6%8E%A5%E5%8F%A3.md
     * @param opt
     */
    function showMoveWindow(opt: { show?: boolean, x?: number, y?: number, width?: number, height?: number, rtl?: boolean }): void
    /**
     * 打开hago的通用分享面板  分享到bbs
     * @see https://kxd-gitlab.yy.com/kxd_3rd/hago_doc/blob/master/zh/internal/arShare.md#hagoShareObject
     * @param opt
     */
    function showSharePanel(opt: { innerShare: string, outerShare: String }): void
    /**
     * 获取进入游戏时的拓展数据
     * @param opt
     */
    function getJumpGameExtend(opt: { success?: (extend: string) => void }): void
    /**
     * 获取频道语音房信息
     * roomId: string, //当前房间Id
     * ownerId: number, //当前房主ID
     * vId: string,     //显示给用户的房间ID
     *  roomName: string  //房间名
     * @see https://git.yy.com/midwares/gameplatform/hago-game-sdk/blob/master/sdk-hago%E6%8E%A5%E5%8F%A3.md
     * @param opt
     */
    function getCurVoiceRoomData(opt: { callback?: (data: { roomId: string, ownerId: number, vId: string, roomName: string }) => void }): void;

    /**
     * 打开h5页面
     * url  h5链接（必填）
     * title  网页标题
     * orientation  横竖屏（ 0为竖屏，1为横屏）
     * backgroundColor  H5页面背景色，例如#ff000000
     * @see https://git.yy.com/midwares/gameplatform/hago-game-sdk/blob/master/sdk-hago%E6%8E%A5%E5%8F%A3.md
     */
    function showWebPage(opt: {
        url: string;
        orientation?: number;
        title?: string;
        backgroundColor?: string;
        isFullScreen?: boolean
    }): void;

    /**
     * 打开充值弹窗  3.42 以上版本
     * @see https://git.yy.com/midwares/gameplatform/hago-game-sdk/blob/master/sdk-hago%E6%8E%A5%E5%8F%A3.md
     */
    function recharge(opt: {
        callback?: (data: { gameId: string, amount: number, currencyType: number, currencyAmount: number, orderId: string, code: number, msg: string }) => void
    }): void;
}
