/// <reference path="./interfaces/IResControl.ts" />
/// <reference path="./interfaces/IUserRender.ts" />


namespace hogame.utils {
    const DIC_REATRY_COUNT: { [originUrl: string]: number } = {}
    const DIC_URL_RESIZE_INFO: { [originUrl: string]: { limitWidth: number, limitHeight: number, resizeUrl: string }[] } = {}
    const DIC_LOADING_CALLBCK: { [resizeUrl: string]: gea.interfaces.base.ICallback[] } = {}
    let MAX_RETRY_COUNT: number = 5
    let RETRY_DURATION: number = 2000

    function getResizedUrl(originUrl: string, limitWidth: number, limitHeight: number): string {
        let result: string
        if (limitWidth > 0 && limitHeight > 0) {
            const list = DIC_URL_RESIZE_INFO[originUrl]
            if (list != null) {
                list.some(value => {
                    if (value.limitWidth >= limitWidth - 100 && value.limitHeight >= limitHeight - 100) {
                        result = value.resizeUrl
                        return true
                    }
                    return false
                })
            }
            if (result == null) {
                result = originUrl + `?x-oss-process=image/resize,h_${limitWidth},w_${limitHeight}`
                cacheResizedUrl(originUrl, limitWidth, limitHeight, result)
            }
        } else {
            result = originUrl
        }
        return result
    }

    function cacheResizedUrl(originUrl: string, limitWidth: number, limitHeight: number, resizeUrl: string): void {
        let list = DIC_URL_RESIZE_INFO[originUrl]
        if (list == null) {
            list = []
            DIC_URL_RESIZE_INFO[originUrl] = list
        }
        list.push({ limitWidth: limitWidth, limitHeight: limitHeight, resizeUrl: resizeUrl })
    }
    class Res implements hogame.interfaces.utils.IResControl {
        retryCount(value: number): Res {
            MAX_RETRY_COUNT = value
            return this
        }
        retryDuration(value: number): Res {
            RETRY_DURATION = value
            return this
        }

        getFrameFromRemote(url: string, callback: (result: cc.Texture2D, originUrl: string) => void, scope?: any, limitWidth?: number, limitHeight?: number): void {
            limitWidth = limitWidth || 0
            limitHeight = limitHeight || limitWidth

            const resizeUrl: string = getResizedUrl(url, limitWidth, limitHeight)

            const texture: cc.Texture2D = cc.resources.get(resizeUrl, cc.Texture2D) as cc.Texture2D
            if (texture) {
                callback.call(scope, texture, url)
            } else {
                let listCallback: gea.interfaces.base.ICallback[] = DIC_LOADING_CALLBCK[resizeUrl]
                if (listCallback == null) {
                    listCallback = []
                    DIC_LOADING_CALLBCK[resizeUrl] = listCallback
                    this.load(resizeUrl, url)
                }
                listCallback.push(gea.callback(callback, scope).callbackLimite(1))
            }
        }

        private load(resizeUrl: string, originUrl: string): void {
            cc.assetManager.loadRemote(resizeUrl, (error: Error, texture: cc.Texture2D): void => {
                if (error || texture == null || texture.nativeUrl == null) {
                    let retryCount: number = DIC_REATRY_COUNT[resizeUrl]
                    if (isNaN(retryCount)) {
                        DIC_REATRY_COUNT[resizeUrl] = retryCount = 0
                    } else if (retryCount >= MAX_RETRY_COUNT) {
                        const listCallback: gea.interfaces.base.ICallback[] = DIC_LOADING_CALLBCK[resizeUrl]
                        if (listCallback) {
                            delete DIC_LOADING_CALLBCK[resizeUrl]
                            listCallback.forEach(value => {
                                // @ts-ignore
                                gea.pool.restore(value)
                            })
                        }
                        this.loadFailed(originUrl, resizeUrl)
                        return
                    }
                    gea.timer.once(RETRY_DURATION, (): void => {
                        DIC_REATRY_COUNT[resizeUrl] = ++retryCount
                        gea.warn(`retry to loadTexture ${retryCount}: ${resizeUrl}`)
                        this.load(resizeUrl, originUrl)
                    }, this)
                } else {
                    // @ts-ignore creator2.1.3增加的属性
                    texture.packable = false
                    delete DIC_REATRY_COUNT[resizeUrl]
                    const listCallback: gea.interfaces.base.ICallback[] = DIC_LOADING_CALLBCK[resizeUrl]
                    if (listCallback) {
                        delete DIC_LOADING_CALLBCK[resizeUrl]
                        listCallback.forEach(value => {
                            value.excute(texture, originUrl)
                        })
                    }
                }
            })
        }

        private loadFailed(originUrl: string, resizeUrl: string): void {
            delete DIC_REATRY_COUNT[resizeUrl]
            gea.error(`texture load failed after retry ${MAX_RETRY_COUNT} times: ${resizeUrl}`)
        }
    }
    export const res: hogame.interfaces.utils.IResControl = new Res()
}
