/// <reference path="./interfaces/IConfig.ts" />

namespace hogame {
    class Config implements interfaces.IConfig {
        private _url: string
        private _gameId: string
        private _uid: string
        get url(): string {
            return this._url
        }

        get gameId(): string {
            return this._gameId
        }

        get uid(): string {
            return this._uid
        }

        setup(config: {
            url?: string,
            gameId?: string,
            uid?: string,
        }): void {
            Object.keys(config).forEach((key: string): void => {
                if (this['_' + key] == null) {
                    this['_' + key] = config[key]
                    if (key === 'uid') {
                        const uidCount: number = hogame.config.uid.length
                        let uid2Number: string = ''
                        for (let i: number = 0; i < uidCount; i++) {
                            if (isNaN(parseInt(hogame.config.uid.charAt(i)))) {
                                uid2Number += hogame.config.uid.charCodeAt(i)
                            } else {
                                uid2Number += hogame.config.uid.charAt(i)
                            }
                        }
                        this._uid = uid2Number
                    }
                }
            })
            if (config.gameId != null) {
                gea.setLogPrefix(`[hogame][${config.gameId}]`)
            }
        }
    }

    export const config: interfaces.IConfig = new Config()
}

if (window['hg']) {
    // @ts-ignore
    hogame.config._uid = hg.getUid().toString()
}
