/// <reference path="./IPoolObject.ts" />

namespace gea.interfaces.base {
    /**
     * 对象池管理中心
     */
    export interface IPoolManager {
        /**
         * 从对象池获取一个实例
         * @param poolClass 继承自对象池基类的class
         * @param args 初始化参数
         */
        borrow<T extends IPoolObject>(poolClass: { prototype: T, new(): T }, ...args: any[]): T
        /**
         * 回收一个实例到对象池
         * @param ins 继承自对象池的实例对象
         * @param args 回收时附带的参数
         */
        restore(ins: IPoolObject, ...args: any[]): void
    }
}
