/// <reference path="../../../gea-base/src/base/Pool.ts" />
/// <reference path="../../../gea-base/src/base/utility/Dispatcher.ts" />
/// <reference path="../../../gea-base/src/base/interfaces/IPoolObject.ts" />
/// <reference path="../../../gea-base/src/base/interfaces/IDestroyAble.ts" />
/// <reference path="../../../gea-base/src/base/Timer.ts" />
/// <reference path="./interfaces/ITweener.ts" />
/// <reference path="./Enums.ts" />
/// <reference path="./Ease.ts" />

namespace gea.tween {
    const _mapTweener: Map<string, Tweener> = new Map()
    const easeOvershootOrAmplitude = 1.70158
    const easePeriod = 0

    class TweenInfo implements interfaces.base.IPoolObject, interfaces.base.IDestroyAble {

        get duration(): number {
            return this._duration
        }

        get totalDuration(): number {
            return this._totalDuration
        }

        get delay(): number {
            return this._delay
        }
        private _tweener: interfaces.tween.ITweener
        private _from: { [key: string]: number }
        private _to: { [key: string]: number }
        private _listProperty: string[]
        private _startCount: number = 0
        private _completeCount: number = 0
        private _startTime: number
        private _reverse: boolean = false
        private _duration: number
        private _totalDuration: number
        private _easeType: gea.enums.tween.ease
        private _delay: number = 0
        private _delayFinishTime: number = 0
        private _repeatCount: number = 0
        private _repeatInterval: number = 0
        private _yoyo: boolean = false
        private _yoyoDelay: number = 0
        private _yoyoing: boolean = false
        private _callbackStart: (tweener: interfaces.tween.ITweener, startCount: number, repeatCount: number, ...args: any) => void
        private _callbackStartScope: any
        private _callbackStartArgs: any[]
        private _callbackComplete: (tweener: interfaces.tween.ITweener, completeCount: number, repeatCount: number, ...args: any) => void
        private _callbackCompleteScope: any
        private _callbackCompleteArgs: any[]
        private _propertyInited: boolean = false
        private _startCallbackInvoked: boolean = false

        callbackAfterBorrow(tweener: interfaces.tween.ITweener, duration: number, propertyFrom: { [key: string]: number }, propertyTo: { [key: string]: number }, option: interfaces.tween.ITweenOption): void {
            this._tweener = tweener
            this._from = propertyFrom || {}
            this._to = propertyTo || {}
            this._duration = duration
            this._propertyInited = this._startCallbackInvoked = false

            option = option || {}

            this._easeType = option.easeType || enums.tween.ease.Linear
            this._delay = option.delay || 0
            this._yoyo = option.yoyo || false
            this._yoyoDelay = option.yoyoDelay || 0
            this._yoyoing = false
            this._reverse = false
            if (option.repeatCount == null) {
                this._repeatCount = 0
            } else {
                if (option.repeatCount < 0) {
                    this._repeatCount = Infinity
                } else {
                    this._repeatCount = option.repeatCount
                }
                this._repeatInterval = option.repeatInterval || 0
            }

            const durationOnce = this._duration + (this._yoyo ? this._yoyoDelay + this._duration : 0)
            this._totalDuration = durationOnce + (this._repeatInterval + durationOnce) * this._repeatCount

            if (option.callbackStart) {
                this._callbackStart = option.callbackStart
                this._callbackStartScope = option.callbackStartScope
                this._callbackStartArgs = option.callbackStartArgs || []
            }

            if (option.callbackCompolete) {
                this._callbackComplete = option.callbackCompolete
                this._callbackCompleteScope = option.callbackCompleteScope
                this._callbackCompleteArgs = option.callbackCompleteArgs || []
            }
        }

        callbackBeforeRestore(): boolean {
            this._tweener = this._from = this._to =
                this._callbackStart = this._callbackStartScope = this._callbackStartArgs =
                this._callbackComplete = this._callbackCompleteScope = this._callbackCompleteArgs = null
            if (this._listProperty) {
                this._listProperty.length = 0
            }
            return true
        }

        destroy(): void {
            gea.pool.restore(this)
        }

        start(reverse: boolean): void {
            this.initProperty()
            this._startCount = this._completeCount = this._delayFinishTime = 0
            this._reverse = reverse
            this._startCallbackInvoked = false
        }

        update(): boolean {
            if (gea.instance.pastTime < this._delayFinishTime) {
                return false
            }
            this.startCallback()
            const pastTime: number = gea.instance.pastTime - this._startTime
            let key: string
            if (pastTime < this._duration) {
                const normalizedTime: number = gea.tween.ease.evaluate(this._easeType, pastTime, this._duration, easeOvershootOrAmplitude, easePeriod)
                let from: number
                let to: number
                for (let i: number = 0; i < this._listProperty.length; i++) {
                    key = this._listProperty[i]
                    from = this._from[key]
                    to = this._to[key]
                    this._tweener.target[key] = (this._yoyoing || (this._reverse && !this._yoyo)) ? (to + (from - to) * normalizedTime) : (from + (to - from) * normalizedTime)
                }
            } else {
                for (let i: number = 0; i < this._listProperty.length; i++) {
                    key = this._listProperty[i]
                    this._tweener.target[key] = (this._yoyoing || (this._reverse && !this._yoyo)) ? this._from[key] : this._to[key]
                }
                this.complete()
                return this._completeCount > this._repeatCount
            }
            return false
        }

        forceComplete(): void {
            let key: string
            for (let i: number = 0; i < this._listProperty.length; i++) {
                key = this._listProperty[i]
                this._tweener.target[key] = (this._yoyoing || (this._reverse && !this._yoyo)) ? this._from[key] : this._to[key]
            }
        }

        private initProperty(): void {
            if (!this._propertyInited) {
                this._propertyInited = true
                const target = this._tweener.target
                Object.keys(this._from).forEach(property => {
                    if (this._to[property] == null) {
                        this._to[property] = target[property]
                    }
                })

                this._listProperty = Object.keys(this._to)
                this._listProperty.forEach(property => {
                    if (this._from[property] == null) {
                        this._from[property] = target[property]
                    }
                })
            }
        }

        private complete(): void {
            this.completeCallback()
            if (this._yoyo) {
                this._yoyoing = !this._yoyoing
                this._yoyoing && (this._delayFinishTime = gea.instance.pastTime + this._yoyoDelay)
            }
        }

        private startCallback(): void {
            if (this._startCallbackInvoked) {
                return
            }
            this._startCallbackInvoked = true
            this._startCount++
            if (this._callbackStart && !this._reverse && (!this._yoyo || !this._yoyoing)) {
                this._callbackStart.call(this._callbackStartScope, this._tweener, this._startCount, this._repeatCount, ...this._callbackStartArgs)
            }
            this._startTime = gea.instance.pastTime
        }

        private completeCallback(): void {
            this._startCallbackInvoked = false
            if (this._yoyo && !this._yoyoing) {
                return
            }
            this._delayFinishTime = gea.instance.pastTime + this._repeatInterval
            this._completeCount++
            if (this._callbackComplete && !this._reverse) {
                this._callbackComplete.call(this._callbackCompleteScope, this._tweener, this._completeCount, this._repeatCount, ...this._callbackCompleteArgs)
            }
        }
    }

    class Tweener implements interfaces.tween.ITweener {
        get discriminator(): gea.discriminator.interfaces.tweener {
            return gea.discriminator.interfaces.tweener
        }
        get totalDuration(): number {
            return this._totalDuration
        }
        get target(): any {
            return this._target
        }

        private _totalDuration: number = 0
        private _target: any
        private _autoDestory: boolean = true

        private _running: boolean = false
        private _startCount: number = 0
        private _completeCount: number = 0
        private _repeatCount: number = 0
        private _repeatInterval: number = 0
        private _yoyo: boolean = false
        private _yoyoDelay: number = 0
        private _listTweenInfo: (TweenInfo | number | gea.interfaces.base.ICallback)[] = []
        private _tweenIndex: number = -1
        private _tweenStep: number = 1
        private _tweeningInfo: TweenInfo

        private _listCallbackStart: {
            callback: (tweener: Tweener, startCount: number, ...args: any[]) => void,
            scope?: any,
            args?: any[],
        }[]

        private _listCallbackUpdate: {
            callback: (tweener: Tweener, ...args: any[]) => void,
            scope?: any,
            args?: any[],
        }[]

        private _listCallbackComplete: {
            callback: (tweener: Tweener, completeCount: number, ...args: any[]) => void,
            scope?: any,
            args?: any[],
        }[]

        destroy(forceComplete: boolean = false): void {
            if (forceComplete) {
                this.forceComplete()
            }
            gea.pool.restore(this)
        }

        delay(value: number): Tweener {
            this._listTweenInfo.push(value)
            return this
        }
        callback(callback: (...args: any[]) => void, scope: any, ...args: any[]): Tweener {
            this._listTweenInfo.push(gea.callback(callback, scope, ...args))
            return this
        }
        repeatCount(value: number): Tweener {
            if (value < 0) {
                this._repeatCount = Infinity
            } else {
                this._repeatCount = value
            }
            return this
        }
        repeatInterval(value: number): Tweener {
            this._repeatInterval = value
            return this
        }
        yoyo(value: boolean): Tweener {
            this._yoyo = !!value
            return this
        }
        yoyoDelay(value: number): Tweener {
            this._yoyoDelay = value
            return this
        }
        start(): Tweener {
            if (!this._running) {
                this._running = true
                this._tweenIndex = -1
                this._tweenStep = 1
                this._startCount = this._completeCount = 0
                this.handleNext()
            }
            return this
        }
        pause(): Tweener {
            gea.warn(`not support yet!`)
            return this
        }
        resume(): Tweener {
            gea.warn(`not support yet!`)
            return this
        }
        stop(): Tweener {
            gea.warn(`not support yet!`)
            return this
        }
        reStart(): Tweener {
            gea.warn(`not support yet!`)
            return this
        }
        from(duration: number, property: { [key: string]: number }, option?: interfaces.tween.ITweenOption): Tweener {
            this.appendTweenInfo(duration, property, null, option)
            return this
        }
        to(duration: number, property: { [key: string]: number }, option: interfaces.tween.ITweenOption): Tweener {
            this.appendTweenInfo(duration, null, property, option)
            return this
        }
        fromTo(duration: number, propertyFrom: { [key: string]: number }, propertyTo: { [key: string]: number }, option: interfaces.tween.ITweenOption): Tweener {
            this.appendTweenInfo(duration, propertyFrom, propertyTo, option)
            return this
        }
        appendCallbackStart(callback: (...args: any[]) => void, scope: any, ...callbackArgs: any[]): Tweener {
            this._listCallbackStart.push({
                callback: callback,
                scope: scope,
                args: callbackArgs,
            })
            return this
        }
        appendCallbackUpdate(callback: (...args: any[]) => void, scope: any, ...callbackArgs: any[]): Tweener {
            this._listCallbackUpdate.push({
                callback: callback,
                scope: scope,
                args: callbackArgs,
            })
            return this
        }
        appendCallbackComplete(callback: (...args: any[]) => void, scope: any, ...callbackArgs: any[]): Tweener {
            this._listCallbackComplete.push({
                callback: callback,
                scope: scope,
                args: callbackArgs,
            })
            return this
        }
        callbackAfterBorrow(target: any, autoDestroy: boolean): void {
            this._totalDuration = 0
            this._target = target
            this._autoDestory = autoDestroy
            this._repeatCount = this._repeatInterval = 0
            this._yoyo = false
            this._listCallbackStart = []
            this._listCallbackUpdate = []
            this._listCallbackComplete = []

            _mapTweener.set(gea.uuid(target), this)
        }

        callbackBeforeRestore(): boolean {
            _mapTweener.delete(gea.uuid(this._target))
            gea.polling.off(this.tweening, this)
            gea.timer.offByScope(this)
            this._running = false
            this._listCallbackStart = this._listCallbackUpdate = this._listCallbackComplete = []
            this._target = this._tweeningInfo = null
            this._listTweenInfo.forEach(tweenInfo => {
                if (tweenInfo instanceof TweenInfo) {
                    tweenInfo.destroy()
                } else if (typeof tweenInfo !== 'number') {
                    // @ts-ignore
                    gea.pool.restore(tweenInfo)
                }
            })
            this._listTweenInfo.length = 0
            return true
        }

        private forceComplete(): Tweener {
            let tweenInfo: TweenInfo
            let tweenInfoIndex: number = this._listTweenInfo.length - 1
            let tweenInfoSearchStep: number = -1
            if (this._yoyo) {
                tweenInfoIndex = 0
                tweenInfoSearchStep = 1
            }
            tweenInfo = this._listTweenInfo[tweenInfoIndex] as TweenInfo
            while (tweenInfo && !(tweenInfo instanceof TweenInfo)) {
                tweenInfoIndex += tweenInfoSearchStep
                tweenInfo = this._listTweenInfo[tweenInfoIndex] as TweenInfo
            }
            if (tweenInfo) {
                tweenInfo.forceComplete()
            }
            return this
        }

        private appendTweenInfo(duration: number, from: { [property: string]: number }, to: { [property: string]: number }, option: interfaces.tween.ITweenOption): void {
            const tweenInfo: TweenInfo = gea.pool.borrow(TweenInfo, this, duration, from, to, option)
            this._totalDuration += tweenInfo.duration
            this._listTweenInfo.push(tweenInfo)
        }

        private handleNext(): void {
            gea.polling.off(this.tweening, this)
            if (this._tweenStep === -1 && this._tweeningInfo && this._tweeningInfo.delay > 0) {
                gea.timer.once(this._tweeningInfo.delay, this.handleNext, this)
                this._tweeningInfo = null
                return
            }
            this._tweenIndex += this._tweenStep
            const tweenInfo: TweenInfo | number | gea.interfaces.base.ICallback = this._listTweenInfo[this._tweenIndex]
            if (tweenInfo == null) {
                this.tweenComplete()
            } else {
                if (typeof tweenInfo === 'number') {
                    this._tweeningInfo = null
                    gea.timer.once(tweenInfo, this.handleNext, this)
                } else if (tweenInfo instanceof TweenInfo) {
                    this._tweeningInfo = tweenInfo;
                    (this._tweeningInfo.delay > 0 && this._tweenStep === 1) ? gea.timer.once(this._tweeningInfo.delay, this.tweenNext, this) : this.tweenNext()
                } else {
                    tweenInfo.excute(this)
                    this.handleNext()
                }
            }
        }

        private tweenNext(): void {
            this._tweenStep === 1 && ++this._startCount && this._tweenIndex === 0 && this._listCallbackStart.forEach(callbackInfo => {
                callbackInfo.callback.call(callbackInfo.scope, this, this._startCount, this._repeatCount, ...callbackInfo.args)
            })
            this._tweeningInfo.start(this._tweenStep === -1)
            gea.polling.on(this.tweening, this)
            this.tweening()
        }

        private tweenComplete(): void {
            this.completeCallback()
            if (this._completeCount > this._repeatCount) {
                this._autoDestory && gea.pool.restore(this)
            } else {
                this._tweeningInfo = null
                this._yoyo ? (this._tweenStep *= -1) : (this._tweenIndex = -1)
                if (this._tweenStep === 1) {
                    this._repeatInterval > 0 ? gea.timer.once(this._repeatInterval, this.handleNext, this) : this.handleNext()
                } else {
                    this._yoyoDelay > 0 ? gea.timer.once(this._yoyoDelay, this.handleNext, this) : this.handleNext()
                }
            }
        }

        private completeCallback(): void {
            if (this._yoyo && this._tweenStep === 1) {
                return
            }
            this._completeCount++
            this._listCallbackComplete.forEach(callbackInfo => {
                callbackInfo.callback.call(callbackInfo.scope, this, this._completeCount, this._repeatCount, ...callbackInfo.args)
            })
        }

        private tweening(): void {
            const finished: boolean = this._tweeningInfo.update()
            let callbackInfo: { callback: (...args: any[]) => void, scope?: any, args?: any[] }
            for (let i: number = 0; i < this._listCallbackUpdate.length; i++) {
                callbackInfo = this._listCallbackUpdate[i]
                callbackInfo.callback.call(callbackInfo.scope, this, ...callbackInfo.args)
            }
            if (finished) {
                this.handleNext()
            }
        }
    }

    /**
     * 追加一个from缓动
     * @param target 被缓动对象
     * @param duration 缓动总时长，单位:`ms`
     * @param property 缓动属性的起始值，目标值为当前值
     * @param option 额外参数
     * + easeType 缓动类型 @see gea.enums.tween.ease
     * + delay 缓动开始前的延迟时间，单位:`ms`
     * + repeatCount 重复次数，默认值为0，表示不重复。<0表示无限重复
     * + repeatInterval 重复间隔，单位:`ms`
     * + yoyo 是否回到缓动开始的位置
     * + yoyoDelay yoyo延迟时间，单位:`ms`
     * + callbackStart 缓动开始的回调
     * + callbackStartScope callbackStart作用域
     * + callbackStartArgs callbackStart额外参数
     * + callbackComplete 此条缓动结束的回调
     * + callbackCompleteScope callbackComplete作用域
     * + callbackCompleteArgs callbackComplete 额外参数
     */
    export function from(target: { [key: string]: any }, duration: number, property: { [key: string]: number }, option?: interfaces.tween.ITweenOption): interfaces.tween.ITweener {
        kill(target)
        return gea.pool.borrow(Tweener, target, true).from(duration, property, option).start()
    }
    /**
     * 追加一个to缓动
     * @param target 被缓动对象
     * @param duration 缓动总时长，单位:`ms`
     * @param property 缓动属性的目标值，起始值为当前值
     * @param option 额外参数
     * + easeType 缓动类型 @see gea.enums.tween.ease
     * + delay 缓动开始前的延迟时间,单位:`ms`
     * + repeatCount 重复次数，默认值为0，表示不重复。<0表示无限重复
     * + repeatInterval 重复间隔，单位:`ms`
     * + yoyo 是否回到缓动开始的位置
     * + yoyoDelay yoyo延迟时间，单位:`ms`
     * + callbackStart 缓动开始的回调
     * + callbackStartScope callbackStart作用域
     * + callbackStartArgs callbackStart额外参数
     * + callbackComplete 此条缓动结束的回调
     * + callbackCompleteScope callbackComplete作用域
     * + callbackCompleteArgs callbackComplete 额外参数
     */
    export function to(target: { [key: string]: any }, duration: number, property: { [key: string]: number }, option?: interfaces.tween.ITweenOption): interfaces.tween.ITweener {
        kill(target)
        return gea.pool.borrow(Tweener, target, true).to(duration, property, option).start()
    }
    /**
     * 追加一个fromTo缓动
     * @target 被缓动对象
     * @param duration 缓动总时长，单位:`ms`
     * @param propertyFrom 缓动的起始属性值
     * @param propertyTo 缓动的目标属性值
     * @param option 额外参数
     * + easeType 缓动类型 @see gea.enums.tween.ease
     * + delay 缓动开始前的延迟时间,单位:`ms`
     * + repeatCount 重复次数，默认值为0，表示不重复。<0表示无限重复
     * + repeatInterval 重复间隔，单位:`ms`
     * + yoyo 是否回到缓动开始的位置
     * + yoyoDelay yoyo延迟时间，单位:`ms`
     * + callbackStart 缓动开始的回调
     * + callbackStartScope callbackStart作用域
     * + callbackStartArgs callbackStart额外参数
     * + callbackComplete 此条缓动结束的回调
     * + callbackCompleteScope callbackComplete作用域
     * + callbackCompleteArgs callbackComplete 额外参数
     */
    export function fromTo(target: { [key: string]: any }, duration: number, propertyFrom: { [key: string]: number }, propertyTo: { [key: string]: number }, option?: interfaces.tween.ITweenOption): interfaces.tween.ITweener {
        kill(target)
        return gea.pool.borrow(Tweener, target, true).fromTo(duration, propertyFrom, propertyTo, option).start()
    }
    /**
     * 立即停止一个缓动
     * @param target 被缓动的对象
     * @param forceComplete 是否强制到结束值
     */
    export function kill(target: any, forceComplete: boolean = false): void {
        const uuid: string = gea.uuid(target)
        if (_mapTweener.has(uuid)) {
            _mapTweener.get(uuid).destroy(forceComplete)
            _mapTweener.delete(uuid)
        }
    }
}
