/// <reference path="./IDestroyAble.ts" />
/// <reference path="../interfaceDiscriminator.ts" />
/// <reference path="./IInterfaceDiscriminator.ts" />


namespace gea.interfaces.base {
    export interface ICallback extends IDestroyAble, IInterfaceDiscriminator {
        readonly discriminator: gea.discriminator.interfaces.callback
        /**
         * 获取剩余回调次数
         */
        callbackLimite(): number
        /**
         * @param value 设置回调次数上限,小于等于0表示无穷大
         */
        callbackLimite(value: number): ICallback
        /**
         * 回调设置
         * @param args 回调参数
         */
        args(...args: any[]): ICallback
        /**
         * 执行一次回调
         * @param extraArgs 额外的回调参数
         */
        excute(...extraArgs: any[]): ICallback
    }
}
