/// <reference path="../interfaces/IInterfaceDiscriminator.ts" />

namespace gea.utility.interfaces {
    /**
     * 辨别一个对象是否实现了某个接口
     * @param target 被判断的对象
     * @param discriminator 接口的discriminator定义
     */
    export function discriminate<T extends gea.interfaces.base.IInterfaceDiscriminator>(target: T, discriminator: string): boolean {
        const targetDiscriminator: string[] | string = target.discriminator
        if (typeof targetDiscriminator === 'string') {
            return targetDiscriminator === discriminator
        } else {
            return targetDiscriminator.indexOf(discriminator) !== -1
        }
    }
}
